import { TypeQuizQuestion } from "./quiz-types";
export const newQAdvanced2: TypeQuizQuestion[] = [
  // ── TYPE 1: The Reformer (IDs 1441,1460) ──
  { id: 1441, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 191, track2Day: 241, category: "Healthy vs Unhealthy", question: "A Type 1 colleague sends a detailed email listing everything wrong with a group project, but ends with 'I know I can be intense about this, let me know if I'm overstepping.' What level of health does this suggest?", options: [{ letter: "A", text: "Unhealthy, they are being passive-aggressive by listing problems" }, { letter: "B", text: "Healthy, they maintain their standards while demonstrating self-awareness about their inner critic's intensity" }, { letter: "C", text: "Average, this is typical One behavior with no special self-awareness" }, { letter: "D", text: "Unhealthy, healthy Ones would never point out problems" }], answer: "B", explanation: "A healthy One retains their eye for improvement but adds metacognition, they can observe their own critical impulse rather than being possessed by it. Riso-Hudson place this capacity at Levels 2-3, where Ones hold standards with humility rather than rigidity." },
  { id: 1442, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 192, track2Day: 242, category: "Healthy vs Unhealthy", question: "An unhealthy Type 1 and an unhealthy Type 8 can both appear controlling. What distinguishes the One's version?", options: [{ letter: "A", text: "The One controls through moral correctness and procedure, framing demands as objective standards rather than personal will" }, { letter: "B", text: "The One controls through intimidation and displays of raw power" }, { letter: "C", text: "There is no meaningful difference, both types are identical when unhealthy" }, { letter: "D", text: "The One becomes passive and withdrawn rather than controlling" }], answer: "A", explanation: "Unhealthy Ones wield control through rightness, 'I'm not being bossy, I'm following the rules.' Their anger is filtered through an impersonal framework of principles. Eights, by contrast, own their power directly. The One's control feels institutional; the Eight's feels personal." },
  { id: 1443, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 193, track2Day: 243, category: "Healthy vs Unhealthy", question: "A Type 1 teacher at a healthy level makes a factual error in front of students. How do they most likely respond?", options: [{ letter: "A", text: "They deny the mistake and double down on their original statement" }, { letter: "B", text: "They laugh it off naturally, correct themselves, and use it as a teaching moment about being open to correction" }, { letter: "C", text: "They become visibly distressed and spend the rest of class apologizing" }, { letter: "D", text: "They ignore it and move on without acknowledgment" }], answer: "B", explanation: "Healthy Ones access Seven-like lightness, they can hold their imperfection with grace. Riso-Hudson note that at Level 2-3, Ones become wise, humane, and accepting of human fallibility, including their own. The ability to laugh at mistakes signals genuine integration." },
  { id: 1444, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 194, track2Day: 244, category: "Misidentification", question: "A person is highly organized, follows rules meticulously, and feels anxious when things are uncertain. They could be a Type 1 or a Type 6. What question best differentiates them?", options: [{ letter: "A", text: "Do you follow rules because they are right, or because breaking them feels dangerous?" }, { letter: "B", text: "Do you prefer working alone or in teams?" }, { letter: "C", text: "Are you more emotional or more logical?" }, { letter: "D", text: "Do you prefer routine or variety?" }], answer: "A", explanation: "Ones follow rules from an internal moral compass, the rule is right regardless of consequences. Sixes follow rules as a safety strategy, the rule protects against threat. A One jaywalking feels guilty; a Six jaywalking feels anxious. The motivation behind identical behavior reveals the type." },
  { id: 1445, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 195, track2Day: 245, category: "Misidentification", question: "Type 1 and Type 5 share intellectual rigor and high standards. A researcher obsessively perfects their methodology before publishing. Which clue suggests they are a 1 rather than a 5?", options: [{ letter: "A", text: "They feel morally obligated to get it right because publishing flawed work would be irresponsible to the field" }, { letter: "B", text: "They fear they don't know enough yet and need more data before feeling competent to publish" }, { letter: "C", text: "They are primarily worried about peer criticism and social embarrassment" }, { letter: "D", text: "They are delaying because they find the research process more enjoyable than the outcome" }], answer: "A", explanation: "Ones delay from moral obligation, publishing imperfect work violates their principles. Fives delay from competency anxiety, they never feel they know enough. The One's perfectionism is ethical; the Five's is epistemic. Both look like meticulousness, but the inner experience differs fundamentally." },
  { id: 1446, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 196, track2Day: 246, category: "Misidentification", question: "A parent insists their teenager follow a strict curfew. If they are a Type 1 rather than a Type 6, which reasoning would they most likely give?", options: [{ letter: "A", text: "'It's the responsible thing to do, young people need structure and discipline to develop properly'" }, { letter: "B", text: "'The world is dangerous at night and I need to know you're safe'" }, { letter: "C", text: "'All the other parents set curfews and we should do the same'" }, { letter: "D", text: "'I want you home so we can spend quality time as a family'" }], answer: "A", explanation: "Ones frame rules through principle and proper development, it's about what's right. Sixes frame the same rule through threat assessment, it's about what's safe. Palmer notes that Ones reference internal standards of correctness while Sixes reference external sources of danger." },
  { id: 1447, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 197, track2Day: 247, category: "Stress Signatures", question: "A Type 1 has been under prolonged work stress for months. Which behavioral shift is most characteristic of their move toward the low side of Four?", options: [{ letter: "A", text: "They become increasingly efficient and productive, channeling stress into work output" }, { letter: "B", text: "They become moody, withdrawn, and resentful, suddenly feeling that no one appreciates how hard they try to do everything right" }, { letter: "C", text: "They become more social and seek support from large groups of friends" }, { letter: "D", text: "They become impulsive and start taking uncharacteristic physical risks" }], answer: "B", explanation: "Under sustained stress, Ones disintegrate toward Four's shadow: self-pity, melancholy, and a sense of being uniquely burdened. They shift from 'I must fix this' to 'Nobody understands how much I sacrifice.' Riso-Hudson note they may become envious of others who seem free from their inner critic." },
  { id: 1448, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 198, track2Day: 248, category: "Stress Signatures", question: "When a Type 1 is stressed at home, which daily behavior change would their partner most likely notice first?", options: [{ letter: "A", text: "Increased nitpicking about household details, how dishes are loaded, how towels are folded, with growing irritability" }, { letter: "B", text: "Complete withdrawal from household responsibilities" }, { letter: "C", text: "Sudden desire to throw elaborate parties and entertain guests" }, { letter: "D", text: "Increased spending on luxury items as a coping mechanism" }], answer: "A", explanation: "Stressed Ones tighten their grip on what they can control, and domestic details become a primary outlet. The inner critic intensifies and externalizes, what was once internal frustration leaks out as criticism of a partner's 'incorrect' way of doing mundane tasks." },
  { id: 1449, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 199, track2Day: 249, category: "Blind Spots", question: "What is the most common blind spot that Type 1s resist hearing from others?", options: [{ letter: "A", text: "That their 'helpful feedback' often lands as harsh criticism, and their body language betrays the anger they claim not to feel" }, { letter: "B", text: "That they are too easygoing and need to set more boundaries" }, { letter: "C", text: "That they are not intelligent enough for their role" }, { letter: "D", text: "That they need to take more risks and be less cautious" }], answer: "A", explanation: "Ones typically have a massive blind spot around their own anger. Because their superego equates anger with moral failure, they reframe it as 'being direct' or 'having high standards.' Partners and colleagues often experience the One's anger long before the One acknowledges it." },
  { id: 1450, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 200, track2Day: 250, category: "Blind Spots", question: "A Type 1 manager believes they treat everyone fairly and equally. What pattern might their team see that the One cannot?", options: [{ letter: "A", text: "That the One unconsciously holds different people to different standards based on how much the One respects them" }, { letter: "B", text: "That the One is too lenient and lets everyone get away with poor work" }, { letter: "C", text: "That the One plays favorites based on personal charm" }, { letter: "D", text: "That the One avoids giving any feedback at all" }], answer: "A", explanation: "Ones believe they apply universal standards, but in practice their inner critic is selective. People they respect get more latitude; those they've judged as 'not trying hard enough' get scrutinized relentlessly. The One genuinely cannot see this inconsistency because it contradicts their self-image of fairness." },
  { id: 1451, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 201, track2Day: 251, category: "Growth Edges", question: "What is the single hardest growth move for most Type 1s?", options: [{ letter: "A", text: "Learning to delegate tasks to others" }, { letter: "B", text: "Allowing themselves to feel and express anger directly rather than converting it into resentment or moral superiority" }, { letter: "C", text: "Becoming more organized and structured" }, { letter: "D", text: "Developing stronger opinions about right and wrong" }], answer: "B", explanation: "The One's central defense is reaction formation, converting 'unacceptable' anger into 'acceptable' moral correction. True growth requires letting anger be anger. Riso-Hudson call this 'holy perfection', the realization that reality is already whole, and their anger is a valid human response, not a moral failing." },
  { id: 1452, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 202, track2Day: 252, category: "Growth Edges", question: "A mature Type 1 who has done significant growth work looks fundamentally different from an average One. Which description best captures this transformation?", options: [{ letter: "A", text: "They abandon all standards and become completely permissive" }, { letter: "B", text: "They hold strong values while genuinely accepting that multiple valid approaches exist, and they can receive criticism without their identity being threatened" }, { letter: "C", text: "They become detached from the world and focused only on inner peace" }, { letter: "D", text: "They become louder and more forceful in advocating their positions" }], answer: "B", explanation: "Mature Ones demonstrate what Riso-Hudson call 'objective rightness', wisdom rather than rigidity. They can say 'this is what I believe' without needing others to agree. The inner critic becomes a quiet advisor rather than a tyrant. They embody principle without self-righteousness." },
  { id: 1453, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 203, track2Day: 253, category: "Cultural Variations", question: "How might a Type 1 raised in a collectivist East Asian culture manifest differently from a Type 1 raised in an individualist Western culture?", options: [{ letter: "A", text: "The East Asian One channels perfectionism toward group harmony and filial duty, while the Western One channels it toward personal moral consistency and individual integrity" }, { letter: "B", text: "East Asian Ones are never perfectionistic because the culture discourages it" }, { letter: "C", text: "Western Ones are always more intense than East Asian Ones" }, { letter: "D", text: "There is no difference, type overrides all cultural influence" }], answer: "A", explanation: "The One's core drive for correctness remains, but the definition of 'correct' is culturally shaped. In collectivist settings, doing right means honoring the group, family, and social hierarchy. In individualist settings, it means personal authenticity and standing by one's own moral code even against the group." },
  { id: 1454, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 204, track2Day: 254, category: "Cultural Variations", question: "Male Type 1s in Western cultures often go unrecognized because:", options: [{ letter: "A", text: "Men cannot be Type 1s" }, { letter: "B", text: "The inner critic and emotional restraint of Ones aligns with masculine gender norms, making it invisible as a type pattern rather than 'just being a man'" }, { letter: "C", text: "Male Ones always mistype as Eights" }, { letter: "D", text: "Western cultures do not have Type 1s" }], answer: "B", explanation: "Type 1 traits, self-control, suppressed emotion, strong opinions about correctness, contained anger, overlap significantly with Western masculine ideals. A male One's rigidity may be praised as 'principled' and their emotional suppression as 'strong,' masking the type pattern beneath cultural expectation." },
  { id: 1455, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 205, track2Day: 255, category: "Subtypes Deep Dive", question: "A self-preservation One is organizing their home for the fifth time this month. Their partner says, 'The house looks fine.' The SP One's internal response is most likely:", options: [{ letter: "A", text: "'They're right, I should relax'" }, { letter: "B", text: "A spike of anxiety because 'fine' feels dangerously close to 'not good enough' and they can see three things that still need fixing" }, { letter: "C", text: "Indifference, they were just bored and looking for something to do" }, { letter: "D", text: "Anger at their partner for not helping" }], answer: "B", explanation: "SP Ones experience worry (Naranjo's 'anxiety') as their dominant emotional backdrop. 'Fine' is insufficient, their survival instinct fuses with perfectionism, making an imperfect home environment feel genuinely unsafe. Chestnut notes SP Ones are the most anxious subtype, resembling Sixes in their vigilance." },
  { id: 1456, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 206, track2Day: 256, category: "Subtypes Deep Dive", question: "A social One volunteers for a community organization. Other volunteers cut corners on procedures. The social One is most likely to:", options: [{ letter: "A", text: "Shrug it off, volunteer work doesn't require perfection" }, { letter: "B", text: "Feel compelled to become the group's moral compass, insisting on proper procedures even if it creates tension and slows progress" }, { letter: "C", text: "Quietly leave and find a better-run organization" }, { letter: "D", text: "Focus on building personal friendships rather than correcting process" }], answer: "B", explanation: "Social Ones feel personally responsible for the group's integrity. Chestnut describes them as 'non-adaptable', they cannot lower their standards to match the group's casual norms. Their internal experience is: if I don't hold the line on what's right, the whole group's moral fabric unravels." },
  { id: 1457, type: 1, difficulty: 5 as 1|2|3|4|5, track1Day: 207, track2Day: 257, category: "Subtypes Deep Dive", question: "A sexual (SX) One in a new relationship discovers their partner has a habit they find morally questionable (e.g., casual dishonesty with acquaintances). The SX One's distinctive response compared to other One subtypes is:", options: [{ letter: "A", text: "They confront it with intense emotional heat, this feels like a betrayal of the intimate bond, and they oscillate between wanting to reform their partner and feeling devastated" }, { letter: "B", text: "They calmly list the logical reasons the habit is wrong" }, { letter: "C", text: "They ignore it to preserve the relationship's harmony" }, { letter: "D", text: "They immediately end the relationship without discussion" }], answer: "A", explanation: "SX Ones channel their reforming passion into intimate bonds with an intensity that surprises people. Chestnut notes they resemble Fours in emotional intensity, their partner's imperfections feel like wounds to the relationship itself. The SX One's correction is personal and hot, not institutional and cold." },
  { id: 1458, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 208, track2Day: 258, category: "Famous Figures", question: "Mahatma Gandhi is commonly typed as a Type 1. Which aspect of his life most clearly demonstrates One's core motivation?", options: [{ letter: "A", text: "His desire for fame and public recognition" }, { letter: "B", text: "His relentless pursuit of moral perfection in every domain of life, diet, celibacy, truth-telling, driven by an internal standard of righteousness" }, { letter: "C", text: "His warmth and desire to be loved by everyone around him" }, { letter: "D", text: "His intellectual curiosity about many different philosophical systems" }], answer: "B", explanation: "Gandhi exemplifies the One's drive to align action with principle in every area of life. His autobiography 'My Experiments with Truth' reveals a relentless inner critic scrutinizing his own behavior. His famous self-discipline was not about willpower but about moral obligation to live correctly." },
  { id: 1459, type: 1, difficulty: 4 as 1|2|3|4|5, track1Day: 209, track2Day: 259, category: "Famous Figures", question: "Martha Stewart is often typed as a 1w2. What makes her a One rather than a Three, given her commercial empire?", options: [{ letter: "A", text: "She shows no interest in success or recognition" }, { letter: "B", text: "Her brand is built on there being a definitively 'right way' to do things, she teaches correct methods, not just impressive results" }, { letter: "C", text: "She is primarily motivated by helping others feel good about themselves" }, { letter: "D", text: "She avoids public appearances and prefers working behind the scenes" }], answer: "B", explanation: "A Three builds a brand around success and image; Stewart's brand is built on correctness, the proper way to fold a napkin, the right recipe, the correct technique. Her famous precision reflects the One's conviction that there is an objectively best way to do everything, and she'll teach you." },
  { id: 1460, type: 1, difficulty: 3 as 1|2|3|4|5, track1Day: 210, track2Day: 260, category: "Famous Figures", question: "Which public figure is commonly typed as a 1w9 in the Enneagram community, and why?", options: [{ letter: "A", text: "Al Gore, his methodical, restrained advocacy for climate action reflects the 1w9's principled mission delivered with Nine-wing composure" }, { letter: "B", text: "Oprah Winfrey, her emotional warmth and desire to connect reflects 1w9 energy" }, { letter: "C", text: "Dwayne 'The Rock' Johnson, his discipline and work ethic make him a classic 1w9" }, { letter: "D", text: "Lady Gaga, her perfectionism in performance reflects 1w9 precision" }], answer: "A", explanation: "Gore's lifelong crusade for environmental policy combines the One's moral conviction with the Nine wing's measured, cerebral delivery. Unlike a 1w2 who would be more interpersonally engaged, Gore's advocacy is data-driven and somewhat detached, classic 1w9 temperament." },
  // ── TYPE 2: The Helper (IDs 1461,1480) ──
  { id: 1461, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 211, track2Day: 261, category: "Healthy vs Unhealthy", question: "A Type 2 friend brings you soup when you're sick, then mentions it three separate times over the next week. This pattern suggests:", options: [{ letter: "A", text: "Average-to-unhealthy Two, the generous act came with strings attached, and they need acknowledgment to feel the giving was worthwhile" }, { letter: "B", text: "Healthy Two, they're just making conversation" }, { letter: "C", text: "This is normal behavior for any type" }, { letter: "D", text: "They are actually a Type 3 seeking recognition" }], answer: "A", explanation: "Healthy Twos give freely without keeping a ledger. When a Two repeatedly references their kindness, it reveals the underlying transaction: I gave, now you owe me gratitude. Riso-Hudson place this at Levels 5-6, where the Two's pride prevents them from seeing the manipulation in their generosity." },
  { id: 1462, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 212, track2Day: 262, category: "Healthy vs Unhealthy", question: "An unhealthy Type 2 discovers their adult child is making major life decisions without consulting them. What is the most characteristic unhealthy Two response?", options: [{ letter: "A", text: "Respecting their child's autonomy and offering support when asked" }, { letter: "B", text: "Feeling betrayed and engineering a crisis to reassert their indispensability, perhaps becoming ill or creating a dramatic emotional situation" }, { letter: "C", text: "Withdrawing completely and cutting off contact" }, { letter: "D", text: "Calmly analyzing the situation and offering detached advice" }], answer: "B", explanation: "At unhealthy levels, Twos resort to coercive strategies when their role as indispensable helper is threatened. Riso-Hudson describe Level 7-8 Twos as manipulative martyrs who create emergencies to regain centrality. The unconscious logic is: if I can't be needed through giving, I'll be needed through crisis." },
  { id: 1463, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 213, track2Day: 263, category: "Healthy vs Unhealthy", question: "A healthy Type 2 at a dinner party notices the host is overwhelmed. How do they respond differently from an average Two?", options: [{ letter: "A", text: "They don't notice, healthy Twos are less attuned to others" }, { letter: "B", text: "They quietly help with dishes without making a show of it, and when the host thanks them, they say 'of course' without needing further acknowledgment" }, { letter: "C", text: "They take over the entire kitchen and reorganize how the host is running the event" }, { letter: "D", text: "They announce loudly to other guests that they're going to help so everyone notices" }], answer: "B", explanation: "Healthy Twos retain their remarkable attunement to others' needs but detach from the need for recognition. The help flows naturally and ends cleanly, no ledger, no expectation. Riso-Hudson describe Level 1-2 Twos as unconditionally loving, giving from overflow rather than from need." },
  { id: 1464, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 214, track2Day: 264, category: "Misidentification", question: "A warm, emotionally available person who frequently anticipates others' needs could be a Type 2 or a Type 9. What distinguishes a Two from a Nine in this scenario?", options: [{ letter: "A", text: "The Two anticipates needs to create a bond and feel valued; the Nine merges with others' needs to avoid conflict and maintain peace" }, { letter: "B", text: "There is no real difference, Twos and Nines are essentially the same" }, { letter: "C", text: "Twos are always more extraverted than Nines" }, { letter: "D", text: "Nines anticipate needs more accurately than Twos" }], answer: "A", explanation: "The crucial difference is energetic: Twos move toward others with directed energy, their helping has an active, almost assertive quality. Nines merge with others passively, their accommodation is about dissolving tension rather than building connection. A Two wants to be seen as the helper; a Nine wants to disappear into harmony." },
  { id: 1465, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 215, track2Day: 265, category: "Misidentification", question: "Type 2 and Type 4 can look similar in their emotional intensity and focus on relationships. A person is deeply emotional and feels misunderstood. What indicates they are a Two rather than a Four?", options: [{ letter: "A", text: "They feel misunderstood specifically because they give so much and others don't reciprocate, their pain centers on unacknowledged sacrifice" }, { letter: "B", text: "They feel misunderstood because they experience emotions others seem incapable of feeling, their pain centers on existential uniqueness" }, { letter: "C", text: "They express their emotions through art and creative work" }, { letter: "D", text: "They suppress their emotions and focus on being productive" }], answer: "A", explanation: "Twos and Fours both feel deeply, but the flavor of their suffering differs. The Two's pain is relational and transactional, 'after everything I've done.' The Four's pain is existential and identity-based, 'no one can understand my inner world.' Palmer notes Twos externalize emotional focus; Fours internalize it." },
  { id: 1466, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 216, track2Day: 266, category: "Misidentification", question: "Someone is highly empathetic and often described as 'the glue' of their friend group. They could be a 2 or a 9. Which behavior pattern points to Type 2?", options: [{ letter: "A", text: "They actively reach out to each person individually, remember personal details, and feel hurt if their efforts aren't acknowledged" }, { letter: "B", text: "They create a calm, accepting atmosphere where everyone feels comfortable but rarely initiate contact themselves" }, { letter: "C", text: "They organize group activities focused on intellectual stimulation" }, { letter: "D", text: "They challenge group members to grow and hold them accountable" }], answer: "A", explanation: "Twos are active connectors, they reach out, remember birthdays, check in after hard days. Nines create passive harmony, they're welcoming when approached but rarely initiate. The Two's social centrality is earned through effort; the Nine's comes from their lack of agenda." },
  { id: 1467, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 217, track2Day: 267, category: "Stress Signatures", question: "A Type 2 is going through a period of feeling unappreciated at work and at home. Which stress behavior reflects their move toward Eight?", options: [{ letter: "A", text: "They become even more selfless and generous, doubling down on giving" }, { letter: "B", text: "They become aggressive and confrontational, openly demanding recognition and making others feel guilty for taking them for granted" }, { letter: "C", text: "They withdraw into intellectual pursuits and stop interacting with people" }, { letter: "D", text: "They become anxious and seek reassurance from authority figures" }], answer: "B", explanation: "Disintegrating toward Eight, the Two's suppressed anger erupts. Years of unacknowledged giving fuel an explosive confrontation: 'After everything I've done for you!' Riso-Hudson describe this as the Two finally claiming the power they've been giving away, but doing so destructively." },
  { id: 1468, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 218, track2Day: 268, category: "Stress Signatures", question: "Which physical stress signal is most characteristic of a Type 2 under prolonged stress?", options: [{ letter: "A", text: "Tension headaches from overthinking analytical problems" }, { letter: "B", text: "Exhaustion and physical depletion from overgiving, often presenting as chest tightness or heart-related sensations, the body protesting what the Two won't say with words" }, { letter: "C", text: "Stomach problems from suppressed fear and anxiety" }, { letter: "D", text: "Back pain from carrying too many physical burdens" }], answer: "B", explanation: "Twos are heart-center types, and their somatic stress often manifests in the chest and cardiovascular system. The body literally aches in the area associated with the heart. Many Enneagram somatic practitioners note that Twos hold tension in their arms and chest, the parts of the body used for reaching out and embracing." },
  { id: 1469, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 219, track2Day: 269, category: "Blind Spots", question: "What is the hardest truth for a Type 2 to accept about themselves?", options: [{ letter: "A", text: "That their giving is not purely selfless, it carries an unconscious expectation of reciprocity, and they are more strategic about whom they help than they realize" }, { letter: "B", text: "That they are not as intelligent as they think" }, { letter: "C", text: "That they need more alone time" }, { letter: "D", text: "That they should be more assertive in professional settings" }], answer: "A", explanation: "The Two's pride (Naranjo's core passion) creates a blind spot specifically around the transactional nature of their love. Acknowledging that their 'unconditional' giving comes with conditions threatens their entire self-image. Palmer notes this is why Twos often resist the Enneagram when they first encounter it." },
  { id: 1470, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 220, track2Day: 270, category: "Blind Spots", question: "A Type 2 insists they have no personal needs and are happiest when serving others. What does this claim actually reveal?", options: [{ letter: "A", text: "That they have achieved genuine selflessness and spiritual maturity" }, { letter: "B", text: "That they have repressed their needs so deeply they genuinely cannot access them, the blind spot is not just hiding needs but having lost contact with them entirely" }, { letter: "C", text: "That they are lying to gain sympathy" }, { letter: "D", text: "That they are a healthy Two who has transcended ego" }], answer: "B", explanation: "This is the Two's most fundamental blind spot: repression of their own needs is so complete that they experience it as having no needs. Riso-Hudson call this the Two's 'self-deception', they cannot see that their relentless focus on others is a strategy to avoid the terror of their own emptiness." },
  { id: 1471, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 221, track2Day: 271, category: "Growth Edges", question: "What is the most transformative, and most resisted, growth practice for a Type 2?", options: [{ letter: "A", text: "Learning to help even more people more effectively" }, { letter: "B", text: "Spending extended time alone without caretaking anyone, sitting with the discomfort of not being needed, and learning to receive without immediately reciprocating" }, { letter: "C", text: "Becoming more socially connected and expanding their network" }, { letter: "D", text: "Developing their intellectual capabilities through formal education" }], answer: "B", explanation: "Solitude is the Two's growth edge because it strips away their primary identity strategy. Without someone to help, the Two must confront the question: 'Who am I when I'm not needed?' Riso-Hudson recommend receptive practices, receiving compliments, receiving help, receiving silence, as the Two's path to integration." },
  { id: 1472, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 222, track2Day: 272, category: "Growth Edges", question: "A Type 2 therapist realizes they chose their career partly because it guarantees being needed. What does mature growth look like for them specifically?", options: [{ letter: "A", text: "Quitting therapy to do something less relational" }, { letter: "B", text: "Continuing the work but developing rigorous boundaries, seeking supervision to catch countertransference, and building a rich personal life that doesn't depend on clients' gratitude" }, { letter: "C", text: "Becoming more emotionally involved with clients to deepen the healing" }, { letter: "D", text: "Switching to a modality that requires no emotional connection" }], answer: "B", explanation: "Growth for a Two doesn't mean abandoning their gifts but holding them with awareness. A mature Two therapist recognizes the ego satisfaction in being needed and creates structures, supervision, boundaries, personal fulfillment outside work, to ensure their helping comes from health rather than hunger." },
  { id: 1473, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 223, track2Day: 273, category: "Cultural Variations", question: "In cultures where women are expected to be nurturing and self-sacrificing, female Type 2s often:", options: [{ letter: "A", text: "Easily recognize their type because it stands out from cultural norms" }, { letter: "B", text: "Go unidentified as Twos because their type behavior is indistinguishable from cultural gender expectations, making it invisible as a personality pattern" }, { letter: "C", text: "Rebel against the nurturing expectation and become assertive" }, { letter: "D", text: "Express their Two-ness exclusively through professional achievement" }], answer: "B", explanation: "When culture reinforces the Two's pattern, the type becomes invisible. A woman in a traditional culture who constantly serves others may be enacting Two strategy or simply following cultural norms, or both. This makes typing women in such cultures particularly challenging and requires examining internal motivation, not just behavior." },
  { id: 1474, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 224, track2Day: 274, category: "Cultural Variations", question: "A male Type 2 in a Western culture that values masculine independence is most likely to:", options: [{ letter: "A", text: "Express his Two-ness openly through nurturing and emotional caretaking" }, { letter: "B", text: "Channel his helping drive through 'masculine' forms, being the provider, the fixer, the protector, while struggling to acknowledge his emotional needs" }, { letter: "C", text: "Completely suppress all Two traits and appear as a different type" }, { letter: "D", text: "Become more emotionally expressive than female Twos" }], answer: "B", explanation: "Male Twos often disguise their helping through gender-acceptable channels: they become the guy who fixes your car, carries your furniture, solves your practical problems. The underlying motivation, being needed and valued, is identical, but the expression shifts from emotional caregiving to practical service." },
  { id: 1475, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 225, track2Day: 275, category: "Subtypes Deep Dive", question: "A self-preservation Two is hosting Thanksgiving dinner. They've been cooking for two days and refuse all offers of help. When a guest brings a dish, the SP Two's most likely internal reaction is:", options: [{ letter: "A", text: "Genuine delight that someone contributed" }, { letter: "B", text: "A flash of anxiety that the guest's dish might be better than theirs, threatening their role as the essential provider" }, { letter: "C", text: "Relief that they have less work to do" }, { letter: "D", text: "Indifference, food is not important to them" }], answer: "B", explanation: "SP Twos express love through material provision, cooking, hosting, creating physical comfort. When someone else provides, it threatens their identity as the essential nurturer. Chestnut notes SP Twos are the most ambivalent about receiving help because their self-worth is built on being the one who gives." },
  { id: 1476, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 226, track2Day: 276, category: "Subtypes Deep Dive", question: "A social Two has become the unofficial coordinator of their community, organizing events, connecting people, knowing everyone's business. When a new person arrives and starts fulfilling the same role, the SO Two:", options: [{ letter: "A", text: "Welcomes them enthusiastically as a fellow helper" }, { letter: "B", text: "Feels deeply threatened and may subtly undermine the newcomer while appearing supportive, because their social position depends on being the irreplaceable connector" }, { letter: "C", text: "Withdraws completely from community involvement" }, { letter: "D", text: "Confronts the newcomer directly and demands they stop" }], answer: "B", explanation: "Social Twos derive identity from social centrality, being the person everyone turns to. A rival threatens their entire power structure. Naranjo's concept of 'ambition' in SO Twos reveals the competitive edge beneath the warmth: they need to be the most important helper, not just any helper." },
  { id: 1477, type: 2, difficulty: 5 as 1|2|3|4|5, track1Day: 227, track2Day: 277, category: "Subtypes Deep Dive", question: "A sexual Two and a sexual Four are both intensely focused on a romantic partner. What is the key experiential difference?", options: [{ letter: "A", text: "The SX Two molds themselves to become irresistible to the partner, while the SX Four expresses their authentic emotional depths to draw the partner in" }, { letter: "B", text: "The SX Two is more emotionally stable than the SX Four" }, { letter: "C", text: "The SX Four is more focused on the partner than the SX Two" }, { letter: "D", text: "There is no meaningful difference in their romantic behavior" }], answer: "A", explanation: "SX Twos shapeshift to become what the beloved desires, their seduction is adaptive and other-focused. SX Fours attract through the magnetism of their own emotional authenticity, their seduction is self-expressive. The Two asks 'what do you need me to be?' while the Four says 'can you handle who I actually am?'" },
  { id: 1478, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 228, track2Day: 278, category: "Famous Figures", question: "Mother Teresa is one of the most commonly cited Type 2 examples. Which aspect of her life reveals the shadow side of Two rather than just the idealized helper image?", options: [{ letter: "A", text: "Her dedication to serving the poor" }, { letter: "B", text: "Her letters revealed decades of spiritual emptiness, she kept giving despite inner desolation, suggesting the Two pattern of deriving identity from service even when the inner life was barren" }, { letter: "C", text: "Her organizational skills in running a global charity" }, { letter: "D", text: "Her public speaking abilities" }], answer: "B", explanation: "Mother Teresa's posthumously published letters revealed profound inner emptiness, a 'dark night of the soul' lasting decades. From a Two perspective, this illuminates how the type can maintain the giving pattern even when it no longer nourishes them, because stopping would mean confronting the void of 'who am I without service?'" },
  { id: 1479, type: 2, difficulty: 4 as 1|2|3|4|5, track1Day: 229, track2Day: 279, category: "Famous Figures", question: "Dolly Parton is frequently typed as a 2w3. What makes the Three wing evident in her expression of Two?", options: [{ letter: "A", text: "She avoids public attention and prefers to help anonymously" }, { letter: "B", text: "Her generosity is highly visible and brand-conscious, from Dollywood to her literacy foundation, she builds institutions of giving that also showcase her image and success" }, { letter: "C", text: "She is withdrawn and intellectual in interviews" }, { letter: "D", text: "She shows no interest in her physical appearance or public persona" }], answer: "B", explanation: "Parton embodies the 2w3 synthesis: genuine warmth and generosity (Two core) amplified through savvy self-presentation and empire-building (Three wing). Her famous line 'It costs a lot of money to look this cheap' reveals the 2w3's knowing use of image in service of connection." },
  { id: 1480, type: 2, difficulty: 3 as 1|2|3|4|5, track1Day: 230, track2Day: 280, category: "Famous Figures", question: "Which historical figure exemplifies the social Two's pattern of gaining influence through indispensability to powerful people?", options: [{ letter: "A", text: "Eleanor Roosevelt, she became a political force by positioning herself as essential advisor and moral conscience to those in power" }, { letter: "B", text: "Albert Einstein, his scientific genius made him indispensable to physics" }, { letter: "C", text: "Amelia Earhart, her adventurous spirit made her a social Two" }, { letter: "D", text: "Henry David Thoreau, his solitary lifestyle at Walden reflects social Two energy" }], answer: "A", explanation: "Eleanor Roosevelt transformed from a shy young woman into one of the most influential figures of the 20th century by becoming indispensable, first to FDR, then to the United Nations. Her power came not from holding office but from being the person everyone needed. This is the social Two's path to influence." },
  // ── TYPE 3: The Achiever (IDs 1481,1500) ──
  { id: 1481, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 231, track2Day: 281, category: "Healthy vs Unhealthy", question: "A Type 3 executive loses a major deal. A healthy Three and an unhealthy Three both feel the loss deeply. What distinguishes their responses?", options: [{ letter: "A", text: "The healthy Three processes the disappointment, learns from it, and recalibrates without their identity being shattered; the unhealthy Three either denies the failure entirely or spirals into shame" }, { letter: "B", text: "The healthy Three shows no emotion; the unhealthy Three cries" }, { letter: "C", text: "Both respond identically because type doesn't affect response to failure" }, { letter: "D", text: "The healthy Three blames others; the unhealthy Three takes responsibility" }], answer: "A", explanation: "The key difference is identity fusion. Unhealthy Threes are so merged with their image of success that failure feels like annihilation, they must deny it or collapse. Healthy Threes have differentiated their identity from their achievements, so failure stings but doesn't destroy their sense of self." },
  { id: 1482, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 232, track2Day: 282, category: "Healthy vs Unhealthy", question: "An unhealthy Type 3 is passed over for a promotion. Over the following weeks, their colleagues notice:", options: [{ letter: "A", text: "They gracefully accept the decision and support the promoted colleague" }, { letter: "B", text: "They subtly rewrite the narrative, minimizing the importance of the role they didn't get while conspicuously pursuing a different, more impressive opportunity" }, { letter: "C", text: "They become openly emotional and ask for support from coworkers" }, { letter: "D", text: "They lose interest in work entirely and stop trying" }], answer: "B", explanation: "Unhealthy Threes protect their image through narrative control. They cannot be seen as having failed, so they reframe reality: 'I didn't really want it' or 'I'm actually pursuing something bigger.' Riso-Hudson call this 'self-deception in the service of image', the Three genuinely believes their own spin." },
  { id: 1483, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 233, track2Day: 283, category: "Healthy vs Unhealthy", question: "A healthy Type 3 at a party is asked 'What do you do?' How does their answer differ from an average Three's?", options: [{ letter: "A", text: "The healthy Three shares what genuinely excites them about their work or life, even if it's not impressive; the average Three leads with their most impressive credential" }, { letter: "B", text: "The healthy Three refuses to answer the question" }, { letter: "C", text: "The healthy Three gives a longer, more detailed answer" }, { letter: "D", text: "There is no difference, all Threes answer this question the same way" }], answer: "A", explanation: "Healthy Threes have reconnected with authentic desire rather than performing for approval. They might say 'I'm really into pottery right now' instead of leading with their VP title. Riso-Hudson note that at Level 2-3, Threes become genuinely inspiring because their energy comes from inner truth rather than external validation." },
  { id: 1484, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 234, track2Day: 284, category: "Misidentification", question: "Both Type 3 and Type 7 are energetic, optimistic, and future-oriented. A person is always starting exciting new projects. What indicates they are a Three rather than a Seven?", options: [{ letter: "A", text: "They carefully select projects based on how they'll look on a résumé and follow through to completion because unfinished work reflects poorly on them" }, { letter: "B", text: "They start projects based on what sounds fun and easily abandon them when something more interesting appears" }, { letter: "C", text: "They start projects to help other people" }, { letter: "D", text: "They prefer working alone rather than in teams" }], answer: "A", explanation: "Threes are strategic about their projects, each one serves their image and trajectory. They finish what they start because completion equals achievement. Sevens are experiential, they chase the stimulation of beginning and lose interest when the novelty fades. The Three asks 'will this advance me?' The Seven asks 'will this be exciting?'" },
  { id: 1485, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 235, track2Day: 285, category: "Misidentification", question: "Type 3 and Type 8 can both appear powerful, confident, and dominant. A CEO commands a room with authority. Which clue suggests they are a Three rather than an Eight?", options: [{ letter: "A", text: "They adapt their communication style for different audiences, polished with the board, casual with engineers, warm with clients, always reading what the room values" }, { letter: "B", text: "They communicate the same way regardless of audience, with blunt directness that some find abrasive" }, { letter: "C", text: "They avoid conflict and defer to others' opinions" }, { letter: "D", text: "They prefer to lead from behind the scenes rather than being visible" }], answer: "A", explanation: "The Three's power is adaptive, they shapeshift to match what each audience respects. The Eight's power is constant, they are who they are regardless of context. A Three CEO reads the room; an Eight CEO sets the room's tone. Palmer describes Threes as chameleons of competence and Eights as immovable forces." },
  { id: 1486, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 236, track2Day: 286, category: "Misidentification", question: "A driven, image-conscious person could be a Type 3 or a social Type 2. They post about their volunteer work on social media. What distinguishes the Three's motivation?", options: [{ letter: "A", text: "The Three posts to build a personal brand of someone who 'gives back', the volunteering serves their image strategy" }, { letter: "B", text: "The Three posts because they genuinely want to inspire others to help" }, { letter: "C", text: "The Two would never post about their volunteer work" }, { letter: "D", text: "Both types have identical motivations for posting" }], answer: "A", explanation: "Threes curate their public image strategically, volunteering becomes content for their personal brand. Social Twos also seek recognition but their core need is to be seen as caring and needed, not successful. The Three's post says 'look what I accomplished'; the Two's post says 'look how much I care about people.'" },
  { id: 1487, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 237, track2Day: 287, category: "Stress Signatures", question: "A Type 3 who has been maintaining a facade of success while privately struggling with failures is most likely to exhibit which stress pattern?", options: [{ letter: "A", text: "They become increasingly energized and productive" }, { letter: "B", text: "They move toward Nine, becoming apathetic, numbing out with TV or food, and losing the drive that defines them, feeling like a fraud who can't even motivate themselves anymore" }, { letter: "C", text: "They become more confrontational and aggressive" }, { letter: "D", text: "They seek deeper emotional connections with friends" }], answer: "B", explanation: "Threes disintegrate toward Nine: the achiever's engine stalls. When the gap between image and reality becomes too large, the Three collapses into Nine-like numbness. Riso-Hudson note this is particularly terrifying for Threes because productivity is their identity, without it, they feel they don't exist." },
  { id: 1488, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 238, track2Day: 288, category: "Stress Signatures", question: "A Type 3 parent is stressed about their own career. How does this stress most commonly leak into their parenting?", options: [{ letter: "A", text: "They become overly permissive and stop setting expectations" }, { letter: "B", text: "They unconsciously pressure their children to achieve and perform, living vicariously through their kids' accomplishments and becoming disproportionately upset by their kids' failures" }, { letter: "C", text: "They withdraw emotionally and become physically absent" }, { letter: "D", text: "They become more nurturing and emotionally available" }], answer: "B", explanation: "Stressed Threes project their achievement anxiety onto their children. A child's poor grade feels like a reflection on the Three parent's worth. The unconscious message becomes: your value depends on your performance, transmitting the Three's core wound to the next generation." },
  { id: 1489, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 239, track2Day: 289, category: "Blind Spots", question: "Type 3s often say 'I'm just being efficient' or 'I'm just focused on results.' What are they typically blind to in these moments?", options: [{ letter: "A", text: "That their 'efficiency' often steamrolls others' feelings and contributions, and they have cut off access to their own emotions to maintain productivity" }, { letter: "B", text: "That they are not actually being efficient" }, { letter: "C", text: "That they should be working even harder" }, { letter: "D", text: "That efficiency is not valued in their workplace" }], answer: "A", explanation: "Threes are blind to the emotional cost of their achievement drive, both to themselves and others. They genuinely do not register the colleague who felt dismissed or the partner who wanted connection, not a solved problem. Their emotional bypass is so smooth they don't know they're doing it." },
  { id: 1490, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 240, track2Day: 290, category: "Blind Spots", question: "A Three's partner says, 'I don't know who you really are.' The Three is genuinely confused because:", options: [{ letter: "A", text: "They are hiding their true self deliberately" }, { letter: "B", text: "They have so seamlessly merged with their performed identity that they genuinely cannot distinguish between who they are and who they present, the mask has become the face" }, { letter: "C", text: "Their partner is being unreasonable" }, { letter: "D", text: "They know exactly who they are and their partner is wrong" }], answer: "B", explanation: "This is the Three's deepest blind spot: identification with persona is so complete that authenticity questions are baffling. They're not consciously hiding, they've lost track of the original self beneath the adaptations. Riso-Hudson call this 'the essential dilemma of Threes: they don't know that they don't know who they are.'" },
  { id: 1491, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 241, track2Day: 291, category: "Growth Edges", question: "What does genuine vulnerability look like for a Type 3 who is doing deep growth work?", options: [{ letter: "A", text: "Sharing a polished story of overcoming adversity that makes them look resilient" }, { letter: "B", text: "Admitting, without spinning it into a growth narrative, that they feel lost, don't know what they actually want, and that their accomplishments haven't made them feel whole" }, { letter: "C", text: "Crying publicly to show they have emotions" }, { letter: "D", text: "Talking about their childhood trauma in therapy-speak" }], answer: "B", explanation: "The Three's growth edge is unnarrated honesty, sharing reality without packaging it as inspiring content. The key is resisting the instinct to turn vulnerability into another performance. True Three growth often feels like failure to them: admitting 'I don't know' without immediately pivoting to 'but here's my plan.'" },
  { id: 1492, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 242, track2Day: 292, category: "Growth Edges", question: "A Type 3 has spent their career optimizing for external markers of success. In midlife, they feel empty despite achieving everything they set out to. What does their growth path require?", options: [{ letter: "A", text: "Setting even more ambitious goals to reignite their drive" }, { letter: "B", text: "Pausing achievement long enough to discover what they actually feel and want, not what looks good, which often means tolerating a terrifying period of not knowing" }, { letter: "C", text: "Retiring and doing nothing" }, { letter: "D", text: "Switching industries to find a more fulfilling career" }], answer: "B", explanation: "The Three's growth requires what Riso-Hudson call 'the pause', a deliberate interruption of the doing-cycle to reconnect with being. This is terrifying because Threes equate stillness with worthlessness. The growth is learning that they are valuable even when they're not producing or performing." },
  { id: 1493, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 243, track2Day: 293, category: "Cultural Variations", question: "Type 3 is often called 'the American type' because:", options: [{ letter: "A", text: "Only Americans can be Type 3" }, { letter: "B", text: "American culture's emphasis on personal achievement, self-branding, and meritocracy mirrors the Three's core drive, making Three traits culturally normative and therefore harder to identify as a personality fixation" }, { letter: "C", text: "American Threes are more successful than Threes in other cultures" }, { letter: "D", text: "The Enneagram was invented in America" }], answer: "B", explanation: "In cultures that reward self-promotion and measure worth by accomplishment, Type 3 behavior becomes the water everyone swims in. This makes American Threes harder to type because their behavior doesn't stand out as unusual, everyone is performing. In cultures that value modesty, Three behavior is more visibly distinctive." },
  { id: 1494, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 244, track2Day: 294, category: "Cultural Variations", question: "A Type 3 raised in a culture that values academic achievement above all else (e.g., parts of East Asia) versus one raised in a culture that values social media influence would likely:", options: [{ letter: "A", text: "Be identical because Threes don't adapt to cultural values" }, { letter: "B", text: "Pursue completely different markers of success, degrees and test scores versus followers and brand deals, while driven by the same core need to be valued for what they achieve" }, { letter: "C", text: "The East Asian Three would reject academic pressure" }, { letter: "D", text: "The social media-oriented Three would be more authentic" }], answer: "B", explanation: "Threes are chameleons of achievement, they read what their environment rewards and become excellent at it. The Three's core motivation (being valued for accomplishment) is constant, but the expression is entirely context-dependent. This is why Threes can look radically different across cultures while sharing the same inner experience." },
  { id: 1495, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 245, track2Day: 295, category: "Subtypes Deep Dive", question: "A self-preservation Three works long hours but never talks about their accomplishments at social gatherings. At a party, they seem quiet and unassuming. This confuses people who expect Threes to be showy because:", options: [{ letter: "A", text: "SP Threes channel their achievement drive into material security and practical competence, not public admiration, they want to be good, not to look good" }, { letter: "B", text: "They are mistyped and not actually a Three" }, { letter: "C", text: "They are an unhealthy Three who has lost their drive" }, { letter: "D", text: "All Threes are quiet at parties" }], answer: "A", explanation: "SP Threes are the counter-type, Chestnut calls their passion 'vanity without vanity.' They suppress the image-focus and instead prove their worth through tireless, practical work. They're often mistaken for Ones or Sixes because they appear diligent rather than flashy. Their Three-ness shows in their inability to stop working." },
  { id: 1496, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 246, track2Day: 296, category: "Subtypes Deep Dive", question: "A social Three carefully curates their LinkedIn profile, attends industry events strategically, and always knows the right people to mention in conversation. Their internal experience during networking is:", options: [{ letter: "A", text: "Genuine enjoyment of meeting interesting people" }, { letter: "B", text: "A constant internal calculation: who in this room has the most status, how can I connect with them, and how should I present myself to match what they value?" }, { letter: "C", text: "Anxiety about being exposed as incompetent" }, { letter: "D", text: "Boredom and a desire to leave" }], answer: "B", explanation: "Social Threes experience networking as a strategic operation. Naranjo connects this to their vanity operating through social prestige, they instinctively map power structures and position themselves optimally. Unlike social Twos who network to be needed, social Threes network to be admired and associated with success." },
  { id: 1497, type: 3, difficulty: 5 as 1|2|3|4|5, track1Day: 247, track2Day: 297, category: "Subtypes Deep Dive", question: "A sexual Three in a romantic relationship discovers their partner is more professionally successful than they are. Their most likely internal response is:", options: [{ letter: "A", text: "Pure pride and joy in their partner's accomplishments" }, { letter: "B", text: "A complex mix of attraction to the partner's success and anxiety about being the 'less impressive' half, potentially driving them to amplify their own attractiveness or achievements to rebalance the dynamic" }, { letter: "C", text: "Complete indifference to their partner's career" }, { letter: "D", text: "Desire to sabotage their partner's success" }], answer: "B", explanation: "SX Threes achieve through personal magnetism and want to be the most desirable person in their intimate world. A more successful partner triggers both admiration and competitive anxiety. Chestnut notes SX Threes often select partners who enhance their image, so being outshone creates an identity crisis within the relationship." },
  { id: 1498, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 248, track2Day: 298, category: "Famous Figures", question: "Oprah Winfrey is commonly typed as a 3w2. What aspect of her career trajectory most clearly demonstrates the Three's core pattern?", options: [{ letter: "A", text: "Her ability to reinvent her brand across decades, from talk show host to media mogul to spiritual teacher, always reading what the culture values and becoming that" }, { letter: "B", text: "Her preference for quiet, behind-the-scenes work" }, { letter: "C", text: "Her strict adherence to one consistent persona throughout her career" }, { letter: "D", text: "Her avoidance of the spotlight and public recognition" }], answer: "A", explanation: "Oprah's genius is the Three's genius: she reads the cultural moment and becomes what it needs. Her evolution from tabloid talk to self-improvement to spiritual teacher tracks exactly with changing American values. The Two wing adds genuine warmth, but the Three core drives the constant reinvention and image mastery." },
  { id: 1499, type: 3, difficulty: 4 as 1|2|3|4|5, track1Day: 249, track2Day: 299, category: "Famous Figures", question: "Tom Cruise is frequently typed as a Type 3 in the Enneagram community. What behavior pattern is most diagnostic?", options: [{ letter: "A", text: "His philosophical interests" }, { letter: "B", text: "His famous insistence on doing his own stunts and the controlled, always-on intensity of his public persona, the relentless performance of competence and the inability to ever appear vulnerable or unprepared" }, { letter: "C", text: "His quiet, introverted off-screen personality" }, { letter: "D", text: "His collaborative approach with directors where he defers to their vision" }], answer: "B", explanation: "Cruise embodies the Three's merger with performance. His insistence on doing his own stunts isn't about thrills (Seven) or proving dominance (Eight), it's about being seen as the person who actually does what others only pretend to. His public persona has zero cracks, demonstrating the Three's total identification with image." },
  { id: 1500, type: 3, difficulty: 3 as 1|2|3|4|5, track1Day: 250, track2Day: 300, category: "Famous Figures", question: "Taylor Swift is often discussed as a Type 3 example. Which pattern is most revealing of her Three structure?", options: [{ letter: "A", text: "Her songwriting talent" }, { letter: "B", text: "Her strategic ability to rebrand across musical eras while maintaining fan loyalty, each 'era' is a carefully crafted persona that matches the cultural moment" }, { letter: "C", text: "Her desire for privacy and avoidance of media attention" }, { letter: "D", text: "Her confrontational, aggressive public disputes" }], answer: "B", explanation: "Swift's era-based career management is textbook Three: she reinvents her image systematically, each time reading what the audience wants next. The re-recording of her albums combines Three achievement drive with strategic image control. Her ability to turn personal narrative into brand is the Three's gift at its most visible." },
  // ── TYPE 4: The Individualist (IDs 1501,1520) ──
  { id: 1501, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 251, track2Day: 301, category: "Healthy vs Unhealthy", question: "A Type 4 artist receives criticism of their work. A healthy Four and an unhealthy Four both feel the sting. How do they diverge?", options: [{ letter: "A", text: "The healthy Four sits with the discomfort, extracts what's useful, and returns to creating; the unhealthy Four spirals into feeling fundamentally flawed and may abandon the project entirely" }, { letter: "B", text: "The healthy Four feels nothing; the unhealthy Four overreacts" }, { letter: "C", text: "Both withdraw for exactly the same amount of time" }, { letter: "D", text: "The healthy Four argues with the critic; the unhealthy Four agrees with everything" }], answer: "A", explanation: "Healthy Fours maintain what Riso-Hudson call 'equanimity', they can hold painful emotions without being consumed by them. The criticism hurts but doesn't define them. Unhealthy Fours fuse criticism with identity: if my work is flawed, I am flawed. This triggers the Four's core wound of deficiency." },
  { id: 1502, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 252, track2Day: 302, category: "Healthy vs Unhealthy", question: "An unhealthy Type 4 in a relationship repeatedly creates emotional crises, dramatic breakups, intense reconciliations, provocative behavior. What is driving this pattern?", options: [{ letter: "A", text: "They are testing whether the partner will stay through the worst of them, because ordinary love feels insufficiently intense to prove they are truly seen and wanted" }, { letter: "B", text: "They genuinely want to end the relationship" }, { letter: "C", text: "They are bored and seeking entertainment" }, { letter: "D", text: "They have no control over their behavior" }], answer: "A", explanation: "Unhealthy Fours unconsciously escalate emotional intensity to test the bond's durability. Ordinary stability feels like abandonment to them, if the partner isn't fighting for the relationship, maybe they don't really care. Riso-Hudson note this push-pull dynamic is the Four's way of seeking proof that they are truly wanted despite their flaws." },
  { id: 1503, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 253, track2Day: 303, category: "Healthy vs Unhealthy", question: "A healthy Type 4 is at a party where everyone is having fun but the conversation feels shallow. How do they handle it differently from an average Four?", options: [{ letter: "A", text: "They withdraw and feel superior to the 'superficial' people" }, { letter: "B", text: "They participate in the lighthearted fun without needing every interaction to be deep, while still gravitating naturally toward meaningful conversations when they arise" }, { letter: "C", text: "They force everyone to discuss deep topics immediately" }, { letter: "D", text: "They leave the party within the first ten minutes" }], answer: "B", explanation: "Healthy Fours access the One's gift of acceptance through integration, they can tolerate ordinary moments without needing to transform or reject them. The ability to enjoy lightness without dismissing it as shallow is a hallmark of Four maturity. They bring depth naturally rather than demanding it." },
  { id: 1504, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 254, track2Day: 304, category: "Misidentification", question: "Both Type 4 and Type 5 can be intensely private, introspective, and feel different from others. A withdrawn person says, 'Nobody really understands me.' What distinguishes a Four from a Five?", options: [{ letter: "A", text: "The Four says it with longing, they want to be understood and the gap between their inner world and others' perception causes pain. The Five says it with resignation, they've concluded understanding is unlikely and have stopped seeking it." }, { letter: "B", text: "The Four is more intelligent; the Five is more emotional" }, { letter: "C", text: "The Five wants to be understood more than the Four does" }, { letter: "D", text: "There is no meaningful difference between the two" }], answer: "A", explanation: "Fours and Fives share withdrawal but differ in emotional orientation. Fours withdraw into feeling, their isolation is painful and yearning. Fives withdraw into thinking, their isolation is protective and preferred. Palmer describes the Four's withdrawal as 'longing at a distance' and the Five's as 'observing from a safe perimeter.'" },
  { id: 1505, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 255, track2Day: 305, category: "Misidentification", question: "Type 4 and Type 6 can both be emotionally reactive and anxious. A person experiences chronic self-doubt and frequently feels like an outsider. What clue points to Four rather than Six?", options: [{ letter: "A", text: "Their self-doubt centers on being fundamentally defective or missing something others have, it's an identity wound, not a safety concern" }, { letter: "B", text: "Their self-doubt centers on whether they can trust their own judgment and whether the world is safe, it's a security concern, not an identity wound" }, { letter: "C", text: "Fours never experience anxiety" }, { letter: "D", text: "Sixes never feel like outsiders" }], answer: "A", explanation: "Fours and Sixes share emotional reactivity but the content differs. The Four's doubt is existential: 'Something is fundamentally wrong with me.' The Six's doubt is relational: 'Can I trust this person/situation?' The Four's outsider feeling is identity-based; the Six's is threat-based. Both can look anxious but the underlying wound is distinct." },
  { id: 1506, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 256, track2Day: 306, category: "Misidentification", question: "A creative, emotionally intense person could be a Type 4 or a sexual Type 2. They write deeply personal poetry about relationships. Which pattern indicates Type 4?", options: [{ letter: "A", text: "The poetry explores their own inner landscape and emotional truth, regardless of whether it connects with anyone else, authenticity matters more than impact" }, { letter: "B", text: "The poetry is designed to make a specific person feel deeply understood and emotionally connected to the writer" }, { letter: "C", text: "They never share their poetry with anyone" }, { letter: "D", text: "They write poetry as a hobby but it's not emotionally important to them" }], answer: "A", explanation: "Fours create to express and discover themselves, the audience is secondary. SX Twos create to forge emotional bonds, the specific person is the point. The Four poet is mining their own depths; the SX Two poet is building a bridge to someone. The Four asks 'is this true?' The Two asks 'will this move them?'" },
  { id: 1507, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 257, track2Day: 307, category: "Stress Signatures", question: "A Type 4 is going through a breakup. In the first weeks, their stress manifests primarily as:", options: [{ letter: "A", text: "Efficient problem-solving and quickly moving on" }, { letter: "B", text: "Moving toward the low side of Two, becoming clingy, overinvolved with friends, and desperately seeking reassurance that they're lovable, while simultaneously resenting their own neediness" }, { letter: "C", text: "Becoming aggressive and confrontational with the ex-partner" }, { letter: "D", text: "Immediately starting a new relationship to avoid the pain" }], answer: "B", explanation: "Fours disintegrate toward Two, becoming uncharacteristically dependent and people-pleasing. The normally self-sufficient Four suddenly needs constant reassurance. Riso-Hudson note this is especially disorienting for Fours, who pride themselves on emotional independence, the neediness feels like a betrayal of their identity." },
  { id: 1508, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 258, track2Day: 308, category: "Stress Signatures", question: "A chronically stressed Type 4 at work starts displaying behaviors their coworkers find confusing. Which pattern is most characteristic?", options: [{ letter: "A", text: "They become hyper-efficient and productivity-focused" }, { letter: "B", text: "They oscillate between dramatic emotional displays seeking support and sharp withdrawal when they feel the support is insufficient or inauthentic" }, { letter: "C", text: "They become the office cheerleader, hiding all negative emotions" }, { letter: "D", text: "They focus entirely on helping coworkers with their problems" }], answer: "B", explanation: "Stressed Fours amplify their emotional range while becoming increasingly difficult to satisfy. They reach out (disintegrating toward Two's neediness) then pull back (feeling the response was inadequate). Colleagues experience this as unpredictability, but for the Four it reflects the internal oscillation between craving connection and fearing its inadequacy." },
  { id: 1509, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 259, track2Day: 309, category: "Blind Spots", question: "What do Type 4s chronically fail to see about their relationship to suffering?", options: [{ letter: "A", text: "That they unconsciously maintain and intensify their suffering because it has become fused with their identity, without pain, they fear they would be ordinary and therefore invisible" }, { letter: "B", text: "That they don't actually suffer as much as they claim" }, { letter: "C", text: "That they should try harder to be happy" }, { letter: "D", text: "That everyone suffers equally and their pain is not special" }], answer: "A", explanation: "Fours have a paradoxical relationship with suffering: they genuinely hurt, but they also unconsciously curate and sustain that hurt because it confirms their specialness. The blind spot is not the pain itself but the ego's investment in maintaining it. Palmer notes Fours often resist happiness because it feels ordinary." },
  { id: 1510, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 260, track2Day: 310, category: "Blind Spots", question: "A Type 4 consistently feels that others have something they lack, a happy childhood, easy confidence, stable relationships. What can't the Four see?", options: [{ letter: "A", text: "That they idealize what's absent and devalue what's present, the grass is always greener, and they would likely feel the same dissatisfaction even if they had what others have" }, { letter: "B", text: "That their childhood was actually happy" }, { letter: "C", text: "That other people's lives are genuinely perfect" }, { letter: "D", text: "That they should simply try harder to get what others have" }], answer: "A", explanation: "The Four's envy (Naranjo's core passion) creates a perceptual distortion: what's available is devalued, what's unavailable is idealized. Riso-Hudson describe this as 'the fundamental attribution error of the heart', Fours attribute to others a wholeness that would likely dissolve under close inspection." },
  { id: 1511, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 261, track2Day: 311, category: "Growth Edges", question: "What is the most counter-intuitive growth practice for a Type 4?", options: [{ letter: "A", text: "Exploring their emotions more deeply through journaling and art" }, { letter: "B", text: "Committing to routine, discipline, and showing up consistently even when they don't feel inspired, learning that action creates feeling rather than waiting for feeling to inspire action" }, { letter: "C", text: "Spending more time alone to deepen their inner world" }, { letter: "D", text: "Reading more books about emotional intelligence" }], answer: "B", explanation: "Fours grow by moving toward One's discipline, the integration direction. This means learning that waiting for the 'right feeling' before acting is the ego's trap. Mature Fours discover that consistent action generates authentic emotion more reliably than emotional indulgence does. Structure becomes liberation, not a cage." },
  { id: 1512, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 262, track2Day: 312, category: "Growth Edges", question: "A mature Type 4 who has done deep growth work relates to their emotions in a fundamentally different way. What does this look like?", options: [{ letter: "A", text: "They no longer feel deep emotions" }, { letter: "B", text: "They experience the full range of emotions without attaching identity to any particular feeling state, sadness passes through without becoming 'I am a sad person,' and joy is welcomed without suspicion" }, { letter: "C", text: "They become emotionally flat and detached" }, { letter: "D", text: "They express only positive emotions and suppress negative ones" }], answer: "B", explanation: "The Four's deepest growth is dis-identification from emotional states. Riso-Hudson describe this as moving from 'I am my feelings' to 'I have feelings.' The mature Four retains their emotional depth and sensitivity but no longer needs any particular emotion to know who they are. They become emotionally free rather than emotionally defined." },
  { id: 1513, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 263, track2Day: 313, category: "Cultural Variations", question: "In cultures that discourage emotional expression (e.g., British 'stiff upper lip' culture), how does a Type 4 typically adapt?", options: [{ letter: "A", text: "They stop being Fours and become another type" }, { letter: "B", text: "They channel their emotional intensity into socially acceptable outlets like dark humor, artistic pursuits, or intellectual melancholy, the core pattern persists but wears cultural camouflage" }, { letter: "C", text: "They become louder and more emotionally expressive to rebel against the culture" }, { letter: "D", text: "They feel no tension between their inner experience and cultural norms" }], answer: "B", explanation: "Fours in emotionally reserved cultures learn to encode their intensity in culturally acceptable forms. British Fours may become masters of irony and understatement; Japanese Fours might channel their aesthetic sensitivity into minimalist art. The Four's essential experience remains, but its expression is culturally sculpted." },
  { id: 1514, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 264, track2Day: 314, category: "Cultural Variations", question: "Male Type 4s in cultures with rigid masculine norms often face a unique challenge. What is it?", options: [{ letter: "A", text: "They have no challenges because Fours are always comfortable with themselves" }, { letter: "B", text: "Their emotional sensitivity and aesthetic orientation conflict with masculine expectations, leading many to develop a tough exterior that masks their Four nature, or to channel their intensity into anger rather than sadness" }, { letter: "C", text: "They are more successful than female Fours in all cultures" }, { letter: "D", text: "They naturally conform to masculine norms without inner conflict" }], answer: "B", explanation: "Male Fours in macho cultures face a double bind: their core orientation toward feeling and beauty conflicts with demands for stoicism and toughness. Many develop counter-phobic presentations, channeling their intensity into dark, aggressive aesthetics or brooding masculinity rather than overt vulnerability." },
  { id: 1515, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 265, track2Day: 315, category: "Subtypes Deep Dive", question: "A self-preservation Four is struggling financially but won't take a stable corporate job. Their friends think they're being impractical. The SP Four's internal experience is:", options: [{ letter: "A", text: "They don't care about money at all" }, { letter: "B", text: "Intense internal suffering, they simultaneously feel they deserve more and believe they must endure hardship as proof of their authenticity, creating a masochistic relationship with material deprivation" }, { letter: "C", text: "Excitement about the adventure of being broke" }, { letter: "D", text: "Complete indifference to their financial situation" }], answer: "B", explanation: "SP Fours are the counter-type: they internalize their envy and suffering rather than expressing it dramatically. Chestnut describes them as 'tenacious', they endure hardship stoically, almost as a badge of authenticity. Their suffering is real but also unconsciously cultivated as proof that they're not 'selling out.'" },
  { id: 1516, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 266, track2Day: 316, category: "Subtypes Deep Dive", question: "A social Four walks into a gathering and immediately senses who the most interesting, creative people are. They then position themselves near those people while subtly displaying markers of their own uniqueness (unusual jewelry, an obscure book). This behavior reflects:", options: [{ letter: "A", text: "Normal social behavior for any type" }, { letter: "B", text: "The SO Four's envy operating through group comparison, they need to be recognized as special within the social field, and they both admire and compete with those they see as uniquely gifted" }, { letter: "C", text: "Social anxiety and a desire to hide" }, { letter: "D", text: "A desire to be ordinary and blend in" }], answer: "B", explanation: "Social Fours experience envy most acutely in group settings, they compare themselves to others and feel the gap between who they are and who they wish they were. Chestnut describes SO Fours as the most openly envious subtype, suffering publicly and sometimes wearing their shame as a kind of distinction." },
  { id: 1517, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 267, track2Day: 317, category: "Subtypes Deep Dive", question: "A sexual Four in a relationship oscillates between intense adoration of their partner and bitter disappointment. During the disappointment phase, they are most likely to:", options: [{ letter: "A", text: "Calmly discuss their concerns and work toward resolution" }, { letter: "B", text: "Express their rage and contempt openly, making the partner feel defective for failing to match the idealized image, then later feel devastated by their own cruelty" }, { letter: "C", text: "Silently withdraw and never mention their dissatisfaction" }, { letter: "D", text: "Seek comfort from friends while maintaining a perfect public image of the relationship" }], answer: "B", explanation: "SX Fours are the most emotionally intense and competitive Four subtype. Chestnut describes them as having a 'hate' quality, when the partner fails to match the idealized image, the SX Four's disappointment becomes contemptuous and cutting. They often immediately regret their harshness, creating cycles of rupture and repair." },
  { id: 1518, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 268, track2Day: 318, category: "Famous Figures", question: "Frida Kahlo is one of the most commonly cited Type 4 examples. Which aspect of her life most clearly embodies the Four's core pattern?", options: [{ letter: "A", text: "Her successful commercial art career" }, { letter: "B", text: "Her transformation of personal suffering, physical pain, emotional betrayal, cultural displacement, into art that made her wounds visible and beautiful" }, { letter: "C", text: "Her desire to be ordinary and blend in with society" }, { letter: "D", text: "Her calm, emotionally stable personality" }], answer: "B", explanation: "Kahlo exemplifies the Four's alchemy: turning pain into beauty and identity into art. Her self-portraits are not mere self-representation but explorations of the wounded self as worthy of attention. Her famous line 'I used to think I was the strangest person in the world' captures the Four's lonely sense of uniqueness." },
  { id: 1519, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 269, track2Day: 319, category: "Famous Figures", question: "Prince (the musician) is often typed as a sexual 4w3. What combination of behaviors supports this typing?", options: [{ letter: "A", text: "His shy, understated public persona" }, { letter: "B", text: "His fusion of intense emotional authenticity with an aggressively unique image, combining the Four's need to be unlike anyone else with the Three wing's drive to be stunning and admired" }, { letter: "C", text: "His preference for conventional musical styles and mainstream acceptance" }, { letter: "D", text: "His collaborative, ego-free approach to making music" }], answer: "B", explanation: "Prince's career demonstrates SX 4w3: emotionally intense artistry (Four core), competitive image mastery (Three wing), and an almost combative uniqueness (SX instinct). He didn't just want to be different, he wanted to be so original that no one could ever replicate him. His secrecy and control over his work reflect the Four's need to protect authentic self-expression." },
  { id: 1520, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 270, track2Day: 320, category: "Famous Figures", question: "Virginia Woolf is commonly typed as a Type 4. Which of her well-known statements best captures the Four's inner world?", options: [{ letter: "A", text: "'One cannot think well, love well, sleep well, if one has not dined well', reflecting practical concerns" }, { letter: "B", text: "'You cannot find peace by avoiding life', reflecting her awareness that the Four's tendency to withdraw into inner experience must be balanced with engaged living" }, { letter: "C", text: "'I am the most successful writer of my generation', reflecting confidence" }, { letter: "D", text: "'The secret of life is to have a task', reflecting a focus on productivity" }], answer: "B", explanation: "Woolf's writing reveals the Four's constant oscillation between rich inner life and the pain of disconnection from the outer world. Her diaries show the Four's characteristic pattern: exquisite sensitivity, profound self-doubt, and the search for meaning through aesthetic experience. Her awareness of her own withdrawal pattern reflects Four insight." },
  // ── TYPE 5: The Investigator (IDs 1521,1540) ──
  { id: 1521, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 271, track2Day: 321, category: "Healthy vs Unhealthy", question: "A Type 5 colleague has expertise the team needs. A healthy Five and an unhealthy Five both have the knowledge. How do they differ in sharing it?", options: [{ letter: "A", text: "The healthy Five shares openly and explains concepts in accessible ways; the unhealthy Five hoards knowledge, shares reluctantly, and uses jargon to maintain superiority" }, { letter: "B", text: "The healthy Five refuses to share; the unhealthy Five overshares" }, { letter: "C", text: "Both share equally because knowledge-sharing isn't related to health level" }, { letter: "D", text: "The healthy Five shares only with management; the unhealthy Five shares with everyone" }], answer: "A", explanation: "Healthy Fives move toward Eight's generosity, they share their resources (including knowledge) freely because they trust they won't be depleted. Unhealthy Fives operate from scarcity: every piece of knowledge shared is a piece of themselves given away. Riso-Hudson note that knowledge hoarding is the Five's version of the Two's emotional withholding." },
  { id: 1522, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 272, track2Day: 322, category: "Healthy vs Unhealthy", question: "An unhealthy Type 5 has been living increasingly in isolation. Their apartment is cluttered with books, they eat sporadically, and they've stopped returning calls. What internal experience drives this?", options: [{ letter: "A", text: "They are simply introverted and recharging" }, { letter: "B", text: "The world feels so overwhelming and depleting that every interaction costs more energy than they can spare, they've retreated to the minimum viable existence to preserve their dwindling inner resources" }, { letter: "C", text: "They are planning a major social event and need quiet preparation time" }, { letter: "D", text: "They are depressed but not in a type-specific way" }], answer: "B", explanation: "Unhealthy Fives experience the world as fundamentally draining. Riso-Hudson describe Levels 7-9 Fives as contracting their life to an increasingly narrow perimeter, cutting off needs (food, sleep, hygiene) to reduce their dependence on the outside world. The isolation is not preference but survival strategy." },
  { id: 1523, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 273, track2Day: 323, category: "Healthy vs Unhealthy", question: "A healthy Type 5 is invited to a friend's birthday party. They attend, stay for two hours, have several warm conversations, then leave. What makes this a sign of health?", options: [{ letter: "A", text: "Healthy Fives never attend parties" }, { letter: "B", text: "They engaged genuinely while honoring their energy limits, they neither forced themselves to stay all night nor avoided the event entirely, showing integration of both connection and self-care" }, { letter: "C", text: "Staying only two hours shows they are still unhealthy" }, { letter: "D", text: "A healthy Five would be the last to leave" }], answer: "B", explanation: "Healthy Fives don't become extraverts, they develop the capacity to engage authentically within their natural limits. The key is presence during engagement rather than endurance. Riso-Hudson describe healthy Fives as genuinely warm and even playful in social settings, surprising people who expect perpetual detachment." },
  { id: 1524, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 274, track2Day: 324, category: "Misidentification", question: "A quiet, observant person who values competence and dislikes small talk could be a Type 5 or a Type 1. They spend hours perfecting a report. What distinguishes the Five's motivation?", options: [{ letter: "A", text: "The Five perfects the report because they fear being caught with incomplete understanding, the anxiety is epistemic, not moral" }, { letter: "B", text: "The Five perfects the report because submitting imperfect work would be morally wrong" }, { letter: "C", text: "Fives never spend time perfecting anything" }, { letter: "D", text: "Both types have identical motivations for perfectionism" }], answer: "A", explanation: "Fives perfect from fear of incompetence, being caught without mastery feels exposing. Ones perfect from moral obligation, submitting flawed work violates their principles. The Five asks 'Do I understand this thoroughly enough?' The One asks 'Is this done correctly?' The anxiety has different roots despite similar behavior." },
  { id: 1525, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 275, track2Day: 325, category: "Misidentification", question: "Type 5 and Type 9 can both appear detached, conflict-avoidant, and low-energy. A person seems disengaged in meetings and rarely shares opinions. What indicates Five rather than Nine?", options: [{ letter: "A", text: "The Five is actively processing and will share sharp, precise observations when they choose to speak, their silence is full of thought, not empty of opinion" }, { letter: "B", text: "The Nine is thinking intensely but choosing not to share" }, { letter: "C", text: "The Five is genuinely empty of thought during meetings" }, { letter: "D", text: "There is no way to distinguish Five silence from Nine silence" }], answer: "A", explanation: "Five silence is loaded, they are observing, categorizing, and forming precise views they'll share selectively. Nine silence is often genuinely merged, they've lost track of their own position by unconsciously absorbing everyone else's. When a Five finally speaks, it's incisive. When a Nine speaks, it often includes everyone's perspective but their own." },
  { id: 1526, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 276, track2Day: 326, category: "Misidentification", question: "An introverted, intellectual person who avoids emotional situations could be a Five or an avoidant Nine. They say, 'I just need time to think about this.' What makes this a Five statement rather than a Nine statement?", options: [{ letter: "A", text: "The Five genuinely needs cognitive processing time and will return with a clear, well-formulated position; the Nine is using the same phrase to defer a confrontation they hope will resolve itself" }, { letter: "B", text: "Only Fives ever need time to think" }, { letter: "C", text: "Nines never say this phrase" }, { letter: "D", text: "The Five is lying; the Nine is being honest" }], answer: "A", explanation: "Fives use withdrawal productively, they retreat, think deeply, and return with clarity. Nines use withdrawal avoidantly, they retreat hoping the issue will disappear. The Five's 'I need to think' leads to a decisive return. The Nine's 'I need to think' often leads to indefinite postponement. Same words, different function." },
  { id: 1527, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 277, track2Day: 327, category: "Stress Signatures", question: "A Type 5 under prolonged stress at work, too many meetings, constant demands for collaboration, begins to show which disintegration pattern?", options: [{ letter: "A", text: "They become more collaborative and people-oriented" }, { letter: "B", text: "They move toward Seven, becoming scattered, anxious, and hyperactive, consuming information or stimulation compulsively rather than with their usual focused depth" }, { letter: "C", text: "They become more organized and structured" }, { letter: "D", text: "They become more emotionally expressive and warm" }], answer: "B", explanation: "Stressed Fives disintegrate toward Seven: their usual focused, deep thinking fragments into restless, scattered consumption. They may binge information, jump between topics, or seek stimulation (unusual for a Five) as a way to outrun the anxiety of depletion. Riso-Hudson describe this as the Five's mind racing rather than concentrating." },
  { id: 1528, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 278, track2Day: 328, category: "Stress Signatures", question: "A Five's partner can tell when the Five is stressed because:", options: [{ letter: "A", text: "The Five becomes more emotionally available and talkative" }, { letter: "B", text: "The Five's energy boundary becomes more rigid, they physically withdraw to smaller spaces, respond to questions with shorter answers, and may become irritable if their remaining alone time is interrupted" }, { letter: "C", text: "The Five becomes loud and dramatic" }, { letter: "D", text: "The Five starts seeking physical affection more frequently" }], answer: "B", explanation: "Fives under stress contract. Their already-defined boundaries tighten, the study door closes more often, answers become monosyllabic, and what felt like comfortable introversion becomes palpable withdrawal. Partners learn to read the Five's energy perimeter like a pressure gauge." },
  { id: 1529, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 279, track2Day: 329, category: "Blind Spots", question: "Type 5s pride themselves on objectivity. What is the fundamental blind spot in this self-assessment?", options: [{ letter: "A", text: "That their 'objectivity' is itself an emotional stance, detachment is a feeling-state they have mistaken for neutrality, and their withdrawal from emotion doesn't eliminate bias but creates a specific kind of bias" }, { letter: "B", text: "That they are actually more objective than other types" }, { letter: "C", text: "That objectivity is not valuable" }, { letter: "D", text: "That they should be more emotional in their analysis" }], answer: "A", explanation: "Fives' deepest blind spot is confusing emotional detachment with objectivity. Naranjo identifies the Five's core passion as avarice (withholding), including withholding of emotional engagement, which they mistake for neutrality. In reality, choosing not to feel is itself an emotional decision that shapes perception as powerfully as any other bias." },
  { id: 1530, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 280, track2Day: 330, category: "Blind Spots", question: "A Five's friend says, 'You always analyze your feelings instead of actually feeling them.' The Five is likely to respond by:", options: [{ letter: "A", text: "Immediately accessing their emotions and crying" }, { letter: "B", text: "Analyzing why their friend said that, inadvertently proving the friend's point while genuinely believing they're engaging with the feedback" }, { letter: "C", text: "Angrily rejecting the feedback" }, { letter: "D", text: "Agreeing completely and changing their behavior immediately" }], answer: "B", explanation: "This is the Five's blind spot in action: they process the feedback intellectually, which is the exact behavior being pointed out. The Five genuinely believes that understanding something cognitively is the same as experiencing it. Palmer notes that Fives must learn that 'knowing about' an emotion is fundamentally different from 'having' the emotion." },
  { id: 1531, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 281, track2Day: 331, category: "Growth Edges", question: "What is the most important, and most frightening, growth edge for a Type 5?", options: [{ letter: "A", text: "Acquiring more knowledge and expertise" }, { letter: "B", text: "Taking decisive action in the world before they feel fully prepared, entering the arena of engagement rather than observing from the sidelines, and discovering they have more inner resources than they feared" }, { letter: "C", text: "Developing better analytical frameworks" }, { letter: "D", text: "Reading more books about personal growth" }], answer: "B", explanation: "The Five's growth direction is Eight, action, engagement, and trusting their own power. Fives perpetually delay action because they never feel 'ready enough.' Growth means acting from 80% preparedness and discovering that contact with the world replenishes rather than depletes them. The fear of running empty is the Five's illusion." },
  { id: 1532, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 282, track2Day: 332, category: "Growth Edges", question: "A Five who has done significant growth work surprises their friends by:", options: [{ letter: "A", text: "Becoming even more withdrawn and cerebral" }, { letter: "B", text: "Showing up physically and emotionally in relationships, initiating contact, expressing needs directly, and tolerating the messiness of intimacy without retreating to analyze it" }, { letter: "C", text: "Abandoning all intellectual interests" }, { letter: "D", text: "Becoming loud and domineering in social settings" }], answer: "B", explanation: "Integrated Fives surprise people because they show up with warmth and directness that seems to contradict the stereotype. They've learned that intimacy, while initially draining, ultimately generates energy. The hallmark of Five growth is choosing presence over observation, being in life rather than studying it." },
  { id: 1533, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 283, track2Day: 333, category: "Cultural Variations", question: "In academic cultures that reward intellectual achievement, Type 5s often:", options: [{ letter: "A", text: "Stand out as unusual and different from their peers" }, { letter: "B", text: "Blend in seamlessly because their natural orientation toward knowledge and expertise is the cultural norm, making their type pattern invisible" }, { letter: "C", text: "Rebel against academic expectations" }, { letter: "D", text: "Struggle more than other types in academic settings" }], answer: "B", explanation: "Just as Threes are invisible in achievement-oriented cultures, Fives are invisible in intellectual cultures. A Five in academia may simply look like 'a dedicated scholar' rather than someone with a personality fixation around knowledge accumulation and emotional detachment. The culture validates and reinforces the Five's strategy." },
  { id: 1534, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 284, track2Day: 334, category: "Cultural Variations", question: "A Type 5 raised in a large, emotionally expressive Mediterranean family versus one raised in a reserved Nordic family would likely:", options: [{ letter: "A", text: "Be identical because type overrides culture" }, { letter: "B", text: "Both withdraw, but the Mediterranean Five develops sharper boundaries to manage constant social demands, while the Nordic Five's withdrawal is culturally supported and therefore less visible as a defensive pattern" }, { letter: "C", text: "The Mediterranean Five would stop being a Five" }, { letter: "D", text: "The Nordic Five would be more emotionally expressive" }], answer: "B", explanation: "The Five's withdrawal is a response to feeling overwhelmed, and context determines how much of a response is needed. In emotionally intense cultures, Fives must work harder to create space, making their boundaries more conspicuous. In reserved cultures, the Five's natural inclination is already the norm, hiding the type pattern." },
  { id: 1535, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 285, track2Day: 335, category: "Subtypes Deep Dive", question: "A self-preservation Five has a small apartment where everything has a designated place. When their roommate moves items or brings guests over unexpectedly, the SP Five:", options: [{ letter: "A", text: "Cheerfully welcomes the disruption" }, { letter: "B", text: "Feels a visceral sense of their personal space being invaded, their home is their energy reserve, and disruptions feel like someone raiding their bank account" }, { letter: "C", text: "Doesn't notice the change" }, { letter: "D", text: "Immediately redecorates to incorporate the new arrangement" }], answer: "B", explanation: "SP Fives are the most fortress-like subtype. Their home is not just shelter but an extension of their psyche, a carefully calibrated environment for managing energy. Chestnut describes SP Fives as having 'castle' energy: the drawbridge is up, and uninvited entry feels like a genuine threat to survival resources." },
  { id: 1536, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 286, track2Day: 336, category: "Subtypes Deep Dive", question: "A social Five has extensive knowledge of an obscure subject. At a gathering, they share their expertise and people are fascinated. Afterwards, the SO Five's internal experience is most likely:", options: [{ letter: "A", text: "Pure enjoyment of the social connection" }, { letter: "B", text: "A complex mix of satisfaction at being valued for their knowledge and anxiety about having spent social energy they now need to replenish, plus worry about whether they revealed too much of themselves" }, { letter: "C", text: "Indifference to others' reactions" }, { letter: "D", text: "Desire to immediately share more at the next gathering" }], answer: "B", explanation: "Social Fives seek connection through expertise, knowledge is their currency for belonging. But sharing always has a cost: they've spent energy and exposed their inner world. Naranjo describes SO Fives as seeking 'totems', idealized groups or knowledge systems that provide belonging without requiring emotional vulnerability." },
  { id: 1537, type: 5, difficulty: 5 as 1|2|3|4|5, track1Day: 287, track2Day: 337, category: "Subtypes Deep Dive", question: "A sexual Five in a romantic relationship has an unusually intense, almost consuming connection with their partner, sharing secrets, late-night conversations, a private world for two. This surprises people who think Fives are always detached because:", options: [{ letter: "A", text: "SX Fives are not really Fives" }, { letter: "B", text: "SX Fives concentrate all their relational energy into one bond, creating extraordinary intimacy within that relationship while remaining withdrawn from the rest of the world, their intensity is narrow but deep" }, { letter: "C", text: "All Fives are secretly very romantic" }, { letter: "D", text: "They are performing closeness to maintain the relationship" }], answer: "B", explanation: "SX Fives are the counter-type, they don't look withdrawn in their intimate relationship because all their relational energy funnels into one person. Chestnut describes them as seeking 'confidence', a trusted other with whom they can share their hidden inner world. Outside this bond, they remain classically Five-like." },
  { id: 1538, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 288, track2Day: 338, category: "Famous Figures", question: "Bill Gates is commonly typed as a Type 5. Which career decision most clearly reflects Five motivation rather than Three achievement?", options: [{ letter: "A", text: "Building Microsoft into the world's largest software company" }, { letter: "B", text: "His shift to philanthropy driven by systematic analysis, studying global health data, identifying maximum-impact interventions, and applying engineering logic to charitable giving" }, { letter: "C", text: "His public speaking and media appearances" }, { letter: "D", text: "His competitive business practices in the 1990s" }], answer: "B", explanation: "Gates's philanthropy reveals Five architecture: he didn't just give money away, he studied problems exhaustively, built analytical frameworks, and applied systems thinking to maximize impact. This 'knowledge-first, then act' approach is quintessentially Five. A Three philanthropist would focus more on visibility; a Five focuses on optimization." },
  { id: 1539, type: 5, difficulty: 4 as 1|2|3|4|5, track1Day: 289, track2Day: 339, category: "Famous Figures", question: "Emily Dickinson is frequently typed as a self-preservation 5w4. Which aspects of her life most strongly support this typing?", options: [{ letter: "A", text: "Her prolific social life and public readings" }, { letter: "B", text: "Her increasing physical withdrawal from the world, her rich interior life expressed through thousands of poems never published in her lifetime, and her ability to observe human experience from a protected distance" }, { letter: "C", text: "Her ambition to be recognized as America's greatest poet" }, { letter: "D", text: "Her emotionally expressive public persona" }], answer: "B", explanation: "Dickinson embodies SP 5w4: the extreme withdrawal into a protected space (she rarely left her room in later years), the vast inner world expressed through private poetry (Five's observation capacity plus Four wing's emotional depth), and the preference for letters over face-to-face contact. Her seclusion wasn't depression but strategy." },
  { id: 1540, type: 5, difficulty: 3 as 1|2|3|4|5, track1Day: 290, track2Day: 340, category: "Famous Figures", question: "Albert Einstein is often typed as a 5w4. Which well-known aspect of his personality reflects the Five's core pattern rather than simply being a 'genius'?", options: [{ letter: "A", text: "His mathematical abilities" }, { letter: "B", text: "His insistence on working alone through thought experiments, his minimal material needs, and his famous comment that 'the monotony and solitude of a quiet life stimulates the creative mind'" }, { letter: "C", text: "His charismatic public speaking" }, { letter: "D", text: "His desire for political power and influence" }], answer: "B", explanation: "Einstein's preference for solitary thought experiments over collaborative lab work, his sparse lifestyle, and his explicit valuing of solitude all reflect Five architecture, not just intelligence but a specific relationship to knowledge and energy. His Four wing shows in the aesthetic dimension of his physics: he sought beautiful, elegant theories." },
  // ── TYPE 6: The Loyalist (IDs 1541,1560) ──
  { id: 1541, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 291, track2Day: 341, category: "Healthy vs Unhealthy", question: "A Type 6 employee is asked to lead a new project with uncertain outcomes. A healthy Six and an unhealthy Six both feel anxiety. How do they differ?", options: [{ letter: "A", text: "The healthy Six acknowledges the fear, prepares thoroughly, and moves forward with courage; the unhealthy Six becomes paralyzed by worst-case scenarios or sabotages the project through excessive contingency planning" }, { letter: "B", text: "The healthy Six feels no anxiety; the unhealthy Six panics" }, { letter: "C", text: "Both handle the situation identically" }, { letter: "D", text: "The healthy Six delegates everything; the unhealthy Six tries to do it alone" }], answer: "A", explanation: "The key distinction is the Six's relationship to their fear, not its absence. Healthy Sixes (Riso-Hudson Levels 1-3) experience fear as information rather than paralysis, they feel the anxiety and act anyway. This is genuine courage. Unhealthy Sixes let fear run the show, either through avoidance or hypervigilant over-preparation." },
  { id: 1542, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 292, track2Day: 342, category: "Healthy vs Unhealthy", question: "An unhealthy counter-phobic Six is often mistaken for a healthy Eight because they both appear fearless. What reveals the Six's underlying pattern?", options: [{ letter: "A", text: "The counter-phobic Six's 'fearlessness' has a reactive, charged quality, they charge at what scares them compulsively, and if you remove the fear, the bravado disappears, because it was never genuine power but anxiety turned inside out" }, { letter: "B", text: "Counter-phobic Sixes are genuinely fearless just like Eights" }, { letter: "C", text: "Eights are actually more anxious than counter-phobic Sixes" }, { letter: "D", text: "There is no way to tell them apart" }], answer: "A", explanation: "The Eight's power is settled, they don't need a threat to activate it. The counter-phobic Six's courage is reactive, it requires something to push against. Palmer notes that counter-phobic Sixes often seek out dangerous situations specifically to prove they're not afraid, while Eights don't need to prove anything about their relationship to fear." },
  { id: 1543, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 293, track2Day: 343, category: "Healthy vs Unhealthy", question: "A healthy Type 6 in a leadership role is often described as the best kind of leader because:", options: [{ letter: "A", text: "They make decisions quickly without consulting anyone" }, { letter: "B", text: "They anticipate problems others miss, build consensus before acting, create structures that protect the team, and their loyalty inspires deep trust from their reports" }, { letter: "C", text: "They avoid all risky decisions" }, { letter: "D", text: "They delegate all responsibility to others" }], answer: "B", explanation: "Healthy Sixes transform their vigilance into exceptional foresight and their loyalty into team-building power. Riso-Hudson note that at Levels 1-3, the Six's gift for detecting danger becomes strategic vision, and their need for security becomes a talent for creating safe environments where others can thrive." },
  { id: 1544, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 294, track2Day: 344, category: "Misidentification", question: "A person is anxious, security-seeking, and compliant with rules. They could be a Type 6 or a Type 9. Both avoid conflict. What key difference separates them?", options: [{ letter: "A", text: "The Six avoids conflict from fear of consequences but has strong opinions they're suppressing; the Nine avoids conflict because they genuinely lose track of their own position and merge with others" }, { letter: "B", text: "Sixes never have strong opinions" }, { letter: "C", text: "Nines are more anxious than Sixes" }, { letter: "D", text: "Both types avoid conflict for identical reasons" }], answer: "A", explanation: "The Six's compliance is strategic, they know what they think but calculate the risk of expressing it. The Nine's compliance is structural, they've actually merged with others' viewpoints and lost access to their own. Push a Six and they'll eventually erupt; push a Nine and they'll genuinely not know what they want." },
  { id: 1545, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 295, track2Day: 345, category: "Misidentification", question: "Both phobic Type 6 and Type 4 can appear anxious, self-doubting, and emotionally reactive. A person frequently questions their own decisions and feels different from others. What distinguishes the Six?", options: [{ letter: "A", text: "The Six's self-doubt is about judgment and safety, 'Am I making the right call? Can I trust my own assessment?', while the Four's self-doubt is about identity and worth, 'Am I fundamentally deficient?'" }, { letter: "B", text: "Sixes never feel different from others" }, { letter: "C", text: "Fours never doubt their decisions" }, { letter: "D", text: "The Six is more creative than the Four" }], answer: "A", explanation: "Six doubt and Four doubt have completely different textures. The Six distrusts their own mind, they seek external validation of their thinking. The Four distrusts their own worth, they seek confirmation of their identity. A Six asks 'am I right?' A Four asks 'am I real?' Both feel uncertain, but about fundamentally different things." },
  { id: 1546, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 296, track2Day: 346, category: "Misidentification", question: "A loyal, responsible person who worries a lot could be a Type 6 or a Type 1. They both follow rules carefully. The most telling difference is:", options: [{ letter: "A", text: "The One follows rules because they're right; the Six follows rules because deviating feels dangerous, the One's relationship to authority is moral, the Six's is protective" }, { letter: "B", text: "Ones are never worried; Sixes are never principled" }, { letter: "C", text: "Ones are more intelligent than Sixes" }, { letter: "D", text: "Both follow rules for identical reasons" }], answer: "A", explanation: "When a One breaks a rule, they feel guilty. When a Six breaks a rule, they feel anxious. The One has an inner moral compass that generates internal standards; the Six has an inner alarm system that scans for threats. Both look compliant, but the One's compliance is principled while the Six's compliance is protective." },
  { id: 1547, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 297, track2Day: 347, category: "Stress Signatures", question: "A Type 6 is going through a period of job insecurity. The first behavioral signs of their stress disintegration toward Three are:", options: [{ letter: "A", text: "They become more relaxed and carefree" }, { letter: "B", text: "They become uncharacteristically competitive and image-conscious, working frantically to prove their value and becoming defensive about their accomplishments when they normally wouldn't care about such things" }, { letter: "C", text: "They withdraw into isolation" }, { letter: "D", text: "They become more trusting and open with colleagues" }], answer: "B", explanation: "Stressed Sixes disintegrate toward Three: their usual collaborative loyalty is replaced by anxious self-promotion. They start performing competence rather than simply being competent. Riso-Hudson note that disintegrating Sixes may suddenly brag about achievements, compete with colleagues, or become obsessed with how they appear to management." },
  { id: 1548, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 298, track2Day: 348, category: "Stress Signatures", question: "A stressed Type 6 planning a family vacation exhibits which characteristic pattern?", options: [{ letter: "A", text: "They spontaneously book a trip with minimal planning and embrace uncertainty" }, { letter: "B", text: "They research obsessively, checking reviews, planning backup itineraries, worrying about everything from weather to food safety, and the planning process generates more anxiety than it relieves" }, { letter: "C", text: "They delegate all planning to someone else without concern" }, { letter: "D", text: "They cancel the vacation entirely to avoid stress" }], answer: "B", explanation: "Stressed Sixes enter a vigilance loop: preparation is meant to reduce anxiety, but each contingency they identify generates new scenarios to worry about. The planning becomes its own source of stress. Partners of Sixes often report that the Six's 'preparation' phase is more exhausting than the event itself." },
  { id: 1549, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 299, track2Day: 349, category: "Blind Spots", question: "What is the primary blind spot that Type 6s have about their own thinking?", options: [{ letter: "A", text: "That their vigilance about external threats masks a deeper distrust of their own inner authority, they project their self-doubt outward, seeing danger in the world rather than recognizing the doubt as internal" }, { letter: "B", text: "That they are not actually anxious" }, { letter: "C", text: "That they think too positively about the world" }, { letter: "D", text: "That they trust authority figures too easily" }], answer: "A", explanation: "Sixes struggle to see that much of what they experience as 'realistic danger assessment' is actually projected self-doubt. The world seems untrustworthy because the Six cannot trust themselves. Palmer notes that Sixes who realize this often experience a profound shift, the enemy was never 'out there' but in their own distrust of their inner guidance." },
  { id: 1550, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 300, track2Day: 350, category: "Blind Spots", question: "A Type 6 prides themselves on being prepared for anything. What do they fail to see about this pattern?", options: [{ letter: "A", text: "That their preparation is always sufficient" }, { letter: "B", text: "That excessive preparation can become a way to avoid taking action, they use 'being ready' as a perpetual excuse to delay stepping into the unknown, which is where actual courage and growth happen" }, { letter: "C", text: "That they don't actually prepare enough" }, { letter: "D", text: "That preparation is unnecessary" }], answer: "B", explanation: "The Six's blind spot around preparation is that it can become an avoidance strategy disguised as responsibility. There's always one more contingency to plan for. The growth edge is recognizing that complete safety is impossible and that at some point, preparation must give way to action despite uncertainty." },
  { id: 1551, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 301, track2Day: 351, category: "Growth Edges", question: "The Six's path of integration moves toward Nine. What does this look like in practice?", options: [{ letter: "A", text: "They become passive and disengaged" }, { letter: "B", text: "They develop the capacity to trust the present moment, to relax vigilance, accept uncertainty as inherent rather than threatening, and discover that most of what they feared never actually happens" }, { letter: "C", text: "They stop caring about safety entirely" }, { letter: "D", text: "They become conflict-avoidant and lose their edge" }], answer: "B", explanation: "Integration toward Nine gives the Six something they desperately need: the ability to be at ease. They access the Nine's gift of acceptance, not passivity, but genuine peace with 'not knowing.' Riso-Hudson describe this as the Six discovering 'inner guidance', learning to trust their own experience rather than perpetually scanning for danger." },
  { id: 1552, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 302, track2Day: 352, category: "Growth Edges", question: "A Six who has been in therapy for years has made significant progress. The clearest sign of their growth is:", options: [{ letter: "A", text: "They no longer feel any fear or anxiety" }, { letter: "B", text: "They can notice a fearful thought arising, acknowledge it without believing it reflexively, and choose to act from trust rather than from worst-case thinking, the anxiety is present but no longer runs the show" }, { letter: "C", text: "They have become the most prepared person in every situation" }, { letter: "D", text: "They now trust every authority figure without question" }], answer: "B", explanation: "Six growth is not about eliminating anxiety but changing one's relationship to it. A mature Six has what Riso-Hudson call 'healthy faith', not blind trust but a grounded confidence that they can handle whatever arises. The fear still visits, but it's a guest, not the host." },
  { id: 1553, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 303, track2Day: 353, category: "Cultural Variations", question: "In high-trust societies (e.g., Scandinavian countries) versus low-trust societies (e.g., countries with unstable governments), Type 6 manifests differently. How?", options: [{ letter: "A", text: "Sixes don't exist in high-trust societies" }, { letter: "B", text: "In high-trust societies, Six vigilance may focus on personal relationship security or health anxieties since systemic threats are lower; in low-trust societies, Six vigilance aligns with realistic threat assessment, making the type harder to distinguish from adaptive behavior" }, { letter: "C", text: "Both environments produce identical Six behavior" }, { letter: "D", text: "High-trust societies have more Sixes than low-trust societies" }], answer: "B", explanation: "The Six's vigilance is innate, but the target shifts based on context. When society is genuinely dangerous, Six behavior looks rational and adaptive. When society is stable, the Six's anxiety becomes more visible because it's directed at lower-probability threats. This is why typing Sixes in unstable environments is particularly difficult." },
  { id: 1554, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 304, track2Day: 354, category: "Cultural Variations", question: "Bren\u00e9 Brown, often typed as a Six, has built a career on vulnerability research. How does this reflect a cultural variation in Six expression?", options: [{ letter: "A", text: "It doesn't relate to her being a Six" }, { letter: "B", text: "As a Six in a culture that rewards fearlessness, she found a way to make her core issue, the relationship between fear and courage, into a contribution, transforming her type's struggle into cultural leadership" }, { letter: "C", text: "Her work contradicts her being a Six" }, { letter: "D", text: "All researchers are Sixes" }], answer: "B", explanation: "Brown's work on vulnerability and courage is deeply Six: she studies the exact territory that Sixes navigate daily, fear, trust, belonging, and the courage to be imperfect. Her cultural context (American emphasis on bravery and self-reliance) creates the perfect stage for a Six to transform their personal struggle into universally resonant wisdom." },
  { id: 1555, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 305, track2Day: 355, category: "Subtypes Deep Dive", question: "A self-preservation Six checks their bank account daily, has extensive emergency supplies, and always knows the nearest exit in any building. Friends call them 'paranoid.' The SP Six experiences this as:", options: [{ letter: "A", text: "Fun and exciting" }, { letter: "B", text: "Not paranoia but common sense, they genuinely cannot understand why others don't prepare for obvious threats, and they feel a baseline anxiety about survival that preparation temporarily soothes" }, { letter: "C", text: "Compulsive behavior they want to stop" }, { letter: "D", text: "Something they do to impress others with their preparedness" }], answer: "B", explanation: "SP Sixes experience their vigilance as rational, it's everyone else who is dangerously naive. Chestnut describes SP Sixes as 'warmth' seekers, they build alliances and secure resources to buffer against perceived threats. Their preparation reduces anxiety temporarily, but the underlying fear constantly generates new scenarios to prepare for." },
  { id: 1556, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 306, track2Day: 356, category: "Subtypes Deep Dive", question: "A social Six is deeply invested in their company's mission and team. When management makes a decision the SO Six sees as threatening team cohesion, they:", options: [{ letter: "A", text: "Quietly comply without objection" }, { letter: "B", text: "Become the voice of the group's concerns, advocating vocally for the team, potentially challenging authority despite their anxiety, because protecting the group's safety feels more important than personal risk" }, { letter: "C", text: "Immediately resign in protest" }, { letter: "D", text: "Try to get promoted to management to change things from within" }], answer: "B", explanation: "Social Sixes are the most visibly dutiful subtype, their loyalty is to the group, and they'll challenge even authority figures to protect collective safety. Naranjo connects this to 'duty', the SO Six becomes the group's sentinel, willing to risk personal consequences to sound the alarm. This is where Six courage is most evident." },
  { id: 1557, type: 6, difficulty: 5 as 1|2|3|4|5, track1Day: 307, track2Day: 357, category: "Subtypes Deep Dive", question: "A sexual Six (counter-phobic) signs up for extreme sports, confronts authority figures, and appears fearless. Internally, their experience is:", options: [{ letter: "A", text: "Genuine fearlessness and excitement" }, { letter: "B", text: "Intense anxiety that they combat by running straight at it, the fear is ever-present but they've developed a reflex of attacking rather than fleeing, and the adrenaline temporarily overrides the underlying dread" }, { letter: "C", text: "Calm calculation about risk-reward ratios" }, { letter: "D", text: "Boredom that they're trying to alleviate through stimulation" }], answer: "B", explanation: "Counter-phobic SX Sixes are the most confusing subtype because their behavior contradicts the fearful Six stereotype. Chestnut describes them as having 'strength/beauty', they confront fear through displays of power and attractiveness. But the fear doesn't disappear; it's the fuel. Remove the threat and the SX Six feels groundless rather than relieved." },
  { id: 1558, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 308, track2Day: 358, category: "Famous Figures", question: "Woody Allen is commonly typed as a Type 6. Which aspect of his filmography most reveals Six psychology?", options: [{ letter: "A", text: "His romantic storylines" }, { letter: "B", text: "His characters' constant anxious internal monologues, catastrophic thinking about relationships and mortality, and the humor he mines from the gap between intellectual understanding and emotional security" }, { letter: "C", text: "His preference for action sequences" }, { letter: "D", text: "His confident, decisive protagonists" }], answer: "B", explanation: "Allen's films are essentially Six consciousness externalized: the characters think obsessively about worst-case scenarios, question every decision, and find that intellectual insight provides zero relief from existential anxiety. The comedy comes from the Six's recognition that knowing your fear is irrational doesn't make it go away." },
  { id: 1559, type: 6, difficulty: 4 as 1|2|3|4|5, track1Day: 309, track2Day: 359, category: "Famous Figures", question: "Mark Twain is sometimes typed as a counter-phobic 6w7. What evidence supports this over typing him as a Seven?", options: [{ letter: "A", text: "His humor was purely lighthearted and escapist" }, { letter: "B", text: "His humor was fundamentally skeptical and questioning, he used wit to challenge authority, expose hypocrisy, and voice doubts about institutions, which reflects the Six's distrust of power combined with Seven-wing levity" }, { letter: "C", text: "He was anxious and avoided public speaking" }, { letter: "D", text: "He showed no interest in social commentary" }], answer: "B", explanation: "Twain's satirical genius reflects counter-phobic Six energy: he confronted the powerful through humor rather than deference. His Seven wing adds the sparkle and verbal dexterity, but the engine is Six skepticism, a deep distrust of authority, institutions, and conventional wisdom that he channeled into some of America's most penetrating social critique." },
  { id: 1560, type: 6, difficulty: 3 as 1|2|3|4|5, track1Day: 310, track2Day: 360, category: "Famous Figures", question: "Ellen DeGeneres is often typed as a 6w7 in the Enneagram community. What behavioral pattern most supports this?", options: [{ letter: "A", text: "Her confrontational interview style" }, { letter: "B", text: "Her use of self-deprecating humor to manage anxiety, her relatability-first persona that avoids seeming threatening, and her loyalty-based relationships in the industry" }, { letter: "C", text: "Her desire for luxury and material success above all else" }, { letter: "D", text: "Her preference for dramatic, intense emotional content" }], answer: "B", explanation: "DeGeneres's public persona reflects classic 6w7: humor as anxiety management (Seven wing), likability as a safety strategy (phobic Six), and carefully maintained relationships with powerful allies (Six loyalty). Her brand of 'be kind' reflects the Six's desire to create a safe, predictable social environment." },
  // ── TYPE 7: The Enthusiast (IDs 1561,1580) ──
  { id: 1561, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 311, track2Day: 361, category: "Healthy vs Unhealthy", question: "A Type 7 is offered two opportunities: a steady position with a great company or a risky startup adventure. A healthy Seven and an average Seven both feel the pull of the startup. What differs?", options: [{ letter: "A", text: "The healthy Seven evaluates both honestly, acknowledging the startup's appeal while recognizing the stable role's genuine merits; the average Seven rationalizes away the stable option's value because commitment triggers their fear of limitation" }, { letter: "B", text: "The healthy Seven always chooses the safe option" }, { letter: "C", text: "The average Seven carefully weighs pros and cons" }, { letter: "D", text: "Both would choose identically because Sevens always pick excitement" }], answer: "A", explanation: "Healthy Sevens can tolerate the discomfort of staying with something good rather than chasing something new. Riso-Hudson note that at Levels 1-3, Sevens develop what they call 'holy sobriety', the capacity to find depth and satisfaction in what's present rather than perpetually seeking the next experience." },
  { id: 1562, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 312, track2Day: 362, category: "Healthy vs Unhealthy", question: "An unhealthy Type 7's pattern of constantly starting new projects but never finishing them is driven by:", options: [{ letter: "A", text: "A genuine abundance of creative ideas" }, { letter: "B", text: "The unconscious strategy of staying in the anticipation phase, where reality hasn't yet disappointed, because completing something means confronting its limitations and their own potential inadequacy" }, { letter: "C", text: "Laziness and lack of discipline" }, { letter: "D", text: "External pressure from others to start new things" }], answer: "B", explanation: "Anticipation is the Seven's drug: the moment of possibility, when everything is still perfect in imagination. Completion brings judgment and limitation, the thing is now finite and can be found wanting. Riso-Hudson describe unhealthy Sevens as trapped in a cycle of 'anticipation addiction' where the future is always more appealing than the present." },
  { id: 1563, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 313, track2Day: 363, category: "Healthy vs Unhealthy", question: "A healthy Type 7 sits with a grieving friend. How do they behave differently from an average Seven?", options: [{ letter: "A", text: "The healthy Seven is present with the grief without trying to fix, reframe, or lighten it; the average Seven unconsciously steers toward positive aspects or changes the subject because the heaviness is intolerable" }, { letter: "B", text: "The healthy Seven cries more than the friend" }, { letter: "C", text: "The average Seven is more present than the healthy Seven" }, { letter: "D", text: "Both avoid the grieving friend entirely" }], answer: "A", explanation: "The capacity to be present with pain, without reframing it, is the hallmark of Seven integration. Moving toward Five's depth, healthy Sevens can tolerate darkness. Average Sevens instinctively deflect: 'At least they lived a good life' or 'Let me tell you something funny', not from callousness but from genuine inability to sit with suffering." },
  { id: 1564, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 314, track2Day: 364, category: "Misidentification", question: "Type 7 and Type 3 are both energetic, optimistic, and success-oriented. At a dinner party, both tell impressive stories. What distinguishes the Seven's storytelling from the Three's?", options: [{ letter: "A", text: "The Seven tells stories for the joy of the experience being relived and the pleasure of entertaining, the story itself is the reward; the Three tells stories that build a narrative of personal success and competence" }, { letter: "B", text: "The Three tells funnier stories" }, { letter: "C", text: "The Seven's stories are shorter" }, { letter: "D", text: "Both tell stories for identical reasons" }], answer: "A", explanation: "Sevens tell stories because storytelling is fun, the audience is a bonus. Threes tell stories strategically, each anecdote reinforces their image. Listen for what the story accomplishes: if it makes the teller look good, suspect Three. If it makes the room feel good, suspect Seven. The Seven is experiencing pleasure; the Three is managing perception." },
  { id: 1565, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 315, track2Day: 365, category: "Misidentification", question: "Both Type 7 and social Type 3 can be charming, upbeat, and socially skilled. A popular, outgoing person lights up every room. What reveals a Seven rather than a Three?", options: [{ letter: "A", text: "The Seven's energy is genuinely scattered across multiple interests and they struggle to stay focused on one path, while the Three's energy is strategically directed toward goals that enhance their image" }, { letter: "B", text: "The Three is more charismatic" }, { letter: "C", text: "Sevens are never socially skilled" }, { letter: "D", text: "Threes are never genuinely enthusiastic" }], answer: "A", explanation: "The Seven's diffuse enthusiasm and the Three's focused ambition create very different life trajectories. A Seven at 40 may have had five careers, traveled extensively, and learned many skills to intermediate level. A Three at 40 has a coherent success narrative with each move building on the last. The Seven maximized experience; the Three maximized achievement." },
  { id: 1566, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 316, track2Day: 366, category: "Misidentification", question: "A person is enthusiastic, imaginative, and dislikes routine. They could be a Type 7 or a Type 4. Both value authenticity and experience. What most clearly distinguishes the Seven?", options: [{ letter: "A", text: "The Seven seeks positive, varied experiences and avoids dwelling on pain, while the Four seeks deep, meaningful experiences and is drawn to exploring emotional darkness" }, { letter: "B", text: "Sevens are more creative than Fours" }, { letter: "C", text: "Fours are more adventurous than Sevens" }, { letter: "D", text: "Both types have identical relationships to suffering" }], answer: "A", explanation: "The Seven and Four are polar opposites in their relationship to suffering. The Seven flees from it toward pleasure and possibility; the Four turns toward it as a source of depth and meaning. A Seven in a sad movie wants it to end; a Four wants to sit with the feeling. This fundamental orientation toward pain is the clearest differentiator." },
  { id: 1567, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 317, track2Day: 367, category: "Stress Signatures", question: "A Type 7 who has been forced into a limiting, monotonous situation (e.g., a long illness recovery) begins showing which stress pattern?", options: [{ letter: "A", text: "They become more patient and accepting" }, { letter: "B", text: "They move toward the low side of One, becoming critical, rigid, and perfectionistic, picking apart everything around them with an uncharacteristic harsh edge because their usual escape routes are blocked" }, { letter: "C", text: "They become more social and seek out new friends" }, { letter: "D", text: "They become more physically active and restless" }], answer: "B", explanation: "Sevens disintegrate toward One: when they can't escape pain through new experiences, their frustration converts into One-like criticism. The normally easygoing Seven becomes snappy, judgmental, and fixated on what's wrong. Riso-Hudson describe this as the Seven's shadow perfectionism emerging, they've always had standards but kept them hidden behind positivity." },
  { id: 1568, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 318, track2Day: 368, category: "Stress Signatures", question: "A Seven's partner knows the Seven is stressed when:", options: [{ letter: "A", text: "The Seven becomes quiet and reflective" }, { letter: "B", text: "The Seven's activity level spikes, they suddenly need to book a trip, start a new project, rearrange furniture, or fill every minute with plans, as if stopping would allow something unbearable to catch up with them" }, { letter: "C", text: "The Seven becomes more emotionally open and vulnerable" }, { letter: "D", text: "The Seven sleeps more than usual" }], answer: "B", explanation: "Pre-disintegration stress in Sevens shows as accelerated escapism: more plans, more activities, more stimulation. The partner sees a manic quality creep in, the Seven's usual joie de vivre becomes frantic rather than joyful. It's the behavioral equivalent of running faster to stay ahead of the pain." },
  { id: 1569, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 319, track2Day: 369, category: "Blind Spots", question: "A Type 7 says 'I'm one of the most self-aware people I know' and genuinely believes it. What are they most likely blind to?", options: [{ letter: "A", text: "That their 'self-awareness' is heavily biased toward positive self-knowledge, they know their strengths, interests, and joys intimately but have systematically avoided knowing their pain, fear, and grief" }, { letter: "B", text: "That they are less intelligent than they think" }, { letter: "C", text: "That they need more hobbies" }, { letter: "D", text: "That others see them as shallow" }], answer: "A", explanation: "Sevens have asymmetric self-knowledge: they know their light side deeply but their shadow is mostly unexplored because they've spent a lifetime avoiding it. Naranjo identifies the Seven's core pattern as 'gluttony' for positive experience coupled with 'charlatan' energy, they can appear more whole than they are because they genuinely don't see what's missing." },
  { id: 1570, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 320, track2Day: 370, category: "Blind Spots", question: "A Seven constantly reframes negative experiences into positive ones: a job loss becomes 'a chance for something better,' a breakup becomes 'an opportunity for growth.' What can't they see?", options: [{ letter: "A", text: "That they are being appropriately optimistic" }, { letter: "B", text: "That the reframing is compulsive rather than chosen, they cannot not do it, and it prevents them from fully processing grief, disappointment, and anger, which then accumulate unmetabolized beneath the positive surface" }, { letter: "C", text: "That they should be more negative" }, { letter: "D", text: "That their friends find their optimism annoying" }], answer: "B", explanation: "The Seven's reframing is their primary defense mechanism, rationalization in the service of pain avoidance. The blind spot is not the reframing itself but its compulsive nature: the Seven literally cannot allow a negative experience to remain negative. This prevents genuine processing and creates a growing reservoir of unfelt emotion." },
  { id: 1571, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 321, track2Day: 371, category: "Growth Edges", question: "What does genuine depth look like for a Type 7 who has done significant growth work?", options: [{ letter: "A", text: "They become serious and lose their sense of humor" }, { letter: "B", text: "They can stay with a single pursuit, relationship, or emotion long enough to discover the richness that only sustained attention reveals, their joy deepens from wide to deep, and they find more satisfaction in less" }, { letter: "C", text: "They stop trying new things entirely" }, { letter: "D", text: "They become pessimistic and cynical" }], answer: "B", explanation: "The Seven's integration toward Five is about discovering that depth provides more genuine satisfaction than breadth. A mature Seven learns what Riso-Hudson call 'holy sobriety', the revelation that a single deep experience contains infinite richness, and that staying still is not death but doorway. They become focused without losing their spark." },
  { id: 1572, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 322, track2Day: 372, category: "Growth Edges", question: "A Seven in a long-term relationship feels the familiar itch to escape, fantasizing about other partners or life paths. What does their growth edge require?", options: [{ letter: "A", text: "Following the fantasy to discover if it's genuinely better" }, { letter: "B", text: "Naming the impulse as their type pattern rather than truth, then choosing to investigate what they're avoiding in the present relationship, the discomfort they're fleeing from is often the exact growth material they need" }, { letter: "C", text: "Suppressing the fantasy and never mentioning it" }, { letter: "D", text: "Opening the relationship to include multiple partners" }], answer: "B", explanation: "The Seven's escape fantasies are signals pointing toward avoided pain. Growth means treating the impulse as information rather than instruction: 'What am I running from right now?' Often, the answer is a difficult conversation, a vulnerable emotion, or a mundane reality. The growth is in staying, not from obligation but from choosing depth over novelty." },
  { id: 1573, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 323, track2Day: 373, category: "Cultural Variations", question: "In cultures that emphasize stoicism and restraint (e.g., traditional Japanese culture), how does a Type 7 typically manifest?", options: [{ letter: "A", text: "They don't exist in those cultures" }, { letter: "B", text: "Their enthusiasm may be channeled into culturally acceptable forms, mastering multiple arts, planning elaborate events, or developing intense private hobbies, while their public persona is more contained than a Western Seven" }, { letter: "C", text: "They openly rebel against all cultural norms" }, { letter: "D", text: "They become identical to the culture's dominant type" }], answer: "B", explanation: "Sevens in restraint-valuing cultures learn to channel their appetitive energy into culturally sanctioned channels. A Japanese Seven might pursue dozens of traditional arts, travel extensively within approved frameworks, or become known for elaborate hospitality. The core Seven pattern, seeking stimulation and avoiding pain, persists but wears cultural clothing." },
  { id: 1574, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 324, track2Day: 374, category: "Cultural Variations", question: "In American culture, which strongly reinforces positivity and optimism, Type 7 patterns are particularly hard to identify because:", options: [{ letter: "A", text: "Americans cannot be Sevens" }, { letter: "B", text: "The culture's emphasis on positive thinking, self-improvement, and 'living your best life' normalizes the Seven's avoidance of suffering, making it invisible as a defense mechanism" }, { letter: "C", text: "American Sevens are more serious than Sevens elsewhere" }, { letter: "D", text: "The Seven pattern is easy to identify in any culture" }], answer: "B", explanation: "American culture is essentially Seven culture, optimism is moral, negativity is weakness, and reinvention is celebrated. A Seven in America can maintain their defense mechanism with full cultural support. The reframing that would seem like denial in other cultures is praised as 'resilience' or 'positive mindset' in American contexts." },
  { id: 1575, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 325, track2Day: 375, category: "Subtypes Deep Dive", question: "A self-preservation Seven creates elaborate meal plans, researches the best restaurants in every city they visit, and has a wine collection. Friends think they're just a 'foodie.' The SP Seven's relationship to food is actually:", options: [{ letter: "A", text: "Purely about nutrition and health" }, { letter: "B", text: "A specific channel for their gluttony, food becomes a reliable source of pleasure and a way to ensure they never experience deprivation, which is the SP Seven's deepest fear" }, { letter: "C", text: "Identical to any food enthusiast's relationship" }, { letter: "D", text: "About impressing others with their culinary knowledge" }], answer: "B", explanation: "SP Sevens channel their insatiable appetite into survival-related pleasures, food, comfort, material security. Chestnut describes them as the most practical Sevens, creating networks of reliable pleasure sources. Their food obsession isn't about food per se but about having guaranteed access to enjoyment, a buffer against the fear of deprivation." },
  { id: 1576, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 326, track2Day: 376, category: "Subtypes Deep Dive", question: "A social Seven is known as the life of every group, telling stories, making plans, ensuring everyone has fun. When the group dynamic turns serious or conflictual, the SO Seven:", options: [{ letter: "A", text: "Deepens into the serious conversation" }, { letter: "B", text: "Feels a compulsive need to lighten the mood, crack a joke, or redirect the group toward something positive, they experience the group's pain as their personal responsibility to fix" }, { letter: "C", text: "Leaves the group immediately" }, { letter: "D", text: "Becomes the most serious person in the room" }], answer: "B", explanation: "Social Sevens serve as the group's mood manager, Naranjo connects their pattern to 'sacrifice' or counter-gluttony, where they disguise their pleasure-seeking as service to the group's enjoyment. When group pain arises, it threatens both the Seven's personal comfort and their social role, creating double pressure to deflect." },
  { id: 1577, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 327, track2Day: 377, category: "Subtypes Deep Dive", question: "A sexual Seven is in a relationship and becomes intensely focused on making their partner's life amazing, planning surprise trips, introducing them to new experiences, painting vivid pictures of their future together. The dark side of this pattern is:", options: [{ letter: "A", text: "There is no dark side, this is purely generous" }, { letter: "B", text: "The SX Seven is unconsciously using the partner as a vessel for their own idealization, they need the relationship to be extraordinary because ordinary love triggers their fear of limitation, and the partner may feel pressured to match the Seven's relentless enthusiasm" }, { letter: "C", text: "The partner always appreciates this behavior" }, { letter: "D", text: "This behavior is characteristic of all Sevens, not just SX Sevens" }], answer: "B", explanation: "SX Sevens project their idealization onto intimate partners and relationships. Chestnut describes them as 'suggestibility', they paint such vivid pictures of possibility that both they and their partner get swept up. When reality falls short of the fantasy (as it must), the SX Seven may feel trapped rather than just disappointed." },
  { id: 1578, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 328, track2Day: 378, category: "Famous Figures", question: "Robin Williams is one of the most commonly cited Type 7 examples. What made his life story particularly revealing of the Seven's shadow?", options: [{ letter: "A", text: "His successful career in comedy" }, { letter: "B", text: "The contrast between his manic, joy-generating public persona and his private struggles with depression and addiction, revealing that the Seven's relentless positivity can mask profound pain that has never been adequately processed" }, { letter: "C", text: "His preference for dramatic roles over comedy" }, { letter: "D", text: "His quiet, introverted offscreen personality" }], answer: "B", explanation: "Williams exemplifies the Seven's tragic paradox: the person who generates the most joy for others may be fleeing the most pain internally. His improvisational genius, the ability to make infinite associative leaps, is the Seven mind at full throttle. His depression and addiction reveal what happens when the running stops and unprocessed grief demands attention." },
  { id: 1579, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 329, track2Day: 379, category: "Famous Figures", question: "Richard Branson is frequently typed as a 7w8. What distinguishes his Seven energy from a Type 3 entrepreneur's?", options: [{ letter: "A", text: "Branson shows no business acumen" }, { letter: "B", text: "Branson's ventures span wildly diverse fields driven by what sounds fun and exciting, airlines, music, space travel, rather than building a coherent empire, and he leads with adventure rather than polished professionalism" }, { letter: "C", text: "Branson is more image-conscious than any Three" }, { letter: "D", text: "Branson avoids risk while Threes embrace it" }], answer: "B", explanation: "A Three entrepreneur builds a brand; Branson builds a playground. His empire's diversity, music to space travel, reflects Seven scatter elevated to a business model. The Eight wing adds the assertiveness to make it happen at scale. A Three would create a more coherent narrative; Branson's story is 'I do what excites me', pure Seven." },
  { id: 1580, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 330, track2Day: 380, category: "Famous Figures", question: "Benjamin Franklin is sometimes typed as a 7w6 by Enneagram historians. What supports this typing?", options: [{ letter: "A", text: "His focus on a single discipline throughout his life" }, { letter: "B", text: "His extraordinary range of interests, inventor, writer, diplomat, scientist, publisher, combined with practical wisdom and a focus on community building that reflects the Six wing's loyalty and civic-mindedness" }, { letter: "C", text: "His solitary, reclusive lifestyle" }, { letter: "D", text: "His rigid moral code and strict self-discipline" }], answer: "B", explanation: "Franklin's life is a catalog of Seven breadth: he excelled in more fields than most people attempt. His Six wing shows in his civic orientation, founding libraries, fire departments, and a university. While a pure Seven might scatter without impact, the 6 wing's loyalty and concern for community gave Franklin's enthusiasm lasting practical form." },
  // ── TYPE 8: The Challenger (IDs 1581,1600) ──
  { id: 1581, type: 8, difficulty: 3 as 1|2|3|4|5, track1Day: 331, track2Day: 381, category: "Healthy vs Unhealthy", question: "A Type 8 discovers a colleague has been treated unfairly by management. A healthy Eight and an unhealthy Eight both respond with anger. What differs?", options: [{ letter: "A", text: "The healthy Eight channels their anger into effective advocacy for the colleague while building alliances; the unhealthy Eight bulldozes into confrontation without strategy, potentially making things worse for the colleague" }, { letter: "B", text: "The healthy Eight suppresses their anger; the unhealthy Eight expresses it" }, { letter: "C", text: "Both respond identically because Eights always react with anger" }, { letter: "D", text: "The healthy Eight ignores the situation; the unhealthy Eight gets involved" }], answer: "A", explanation: "The difference is in the relationship between anger and effectiveness. Healthy Eights use their power as an instrument for justice, their anger serves the cause. Unhealthy Eights are used by their anger, it serves their ego's need for dominance. Riso-Hudson describe healthy Eights as 'magnanimous champions' who empower others." },
  { id: 1582, type: 8, difficulty: 4 as 1|2|3|4|5, track1Day: 332, track2Day: 382, category: "Healthy vs Unhealthy", question: "An unhealthy Type 8 perceives betrayal from a trusted friend. Their reaction reveals the Eight's deepest wound because:", options: [{ letter: "A", text: "They calmly discuss it and move on" }, { letter: "B", text: "The betrayal triggers a scorched-earth response wildly disproportionate to the offense, they cut the person off completely and may seek to destroy their reputation, because vulnerability was the Eight's greatest risk and it has now been punished" }, { letter: "C", text: "They become dependent and clingy toward the friend" }, { letter: "D", text: "They blame themselves for the betrayal" }], answer: "B", explanation: "Unhealthy Eights' response to betrayal reveals their core terror: being controlled or harmed through vulnerability. Every time they opened up, they took a risk. Betrayal confirms their deepest belief that vulnerability is weakness. Riso-Hudson note that at Levels 7-9, Eights become ruthless precisely because they once trusted and were wounded." },
  { id: 1583, type: 8, difficulty: 3 as 1|2|3|4|5, track1Day: 333, track2Day: 383, category: "Healthy vs Unhealthy", question: "A healthy Type 8 is leading a team meeting. What surprises people who expect Eights to dominate?", options: [{ letter: "A", text: "They dominate even more aggressively than expected" }, { letter: "B", text: "They create space for quieter voices, actively protect less powerful team members from being talked over, and show genuine tenderness when someone is struggling" }, { letter: "C", text: "They let someone else run the meeting entirely" }, { letter: "D", text: "They focus solely on efficiency and ignore interpersonal dynamics" }], answer: "B", explanation: "Healthy Eights integrate toward Two, their power becomes protective rather than dominating. They use their natural authority to amplify others rather than overshadow them. Riso-Hudson describe Level 1-3 Eights as heroic champions who combine strength with magnanimity, using their force to uplift the vulnerable." },
  { id: 1584, type: 8, difficulty: 4 as 1|2|3|4|5, track1Day: 334, track2Day: 384, category: "Misidentification", question: "Both Type 8 and Type 3 can be ambitious, assertive, and successful. A powerful executive could be either type. What behavior most clearly indicates Eight over Three?", options: [{ letter: "A", text: "The Eight doesn't care about looking good, they'll be blunt, make enemies, and sacrifice their reputation to maintain control, while a Three would modulate their behavior to preserve their image" }, { letter: "B", text: "The Three is more successful" }, { letter: "C", text: "The Eight is more charming" }, { letter: "D", text: "Both types behave identically in executive roles" }], answer: "A", explanation: "Eights prioritize power and autonomy over image. They'll burn bridges, alienate stakeholders, and create enemies if it means maintaining control. Threes never sacrifice image, they find ways to be powerful while still looking good. The Eight asks 'who's in charge?' The Three asks 'how do I look?' These are fundamentally different drives." },
  { id: 1585, type: 8, difficulty: 5 as 1|2|3|4|5, track1Day: 335, track2Day: 385, category: "Misidentification", question: "A counter-phobic Type 6 and a Type 8 both confront a bully at work. How can you tell them apart?", options: [{ letter: "A", text: "The Eight confronts from a place of genuine power, they feel big inside and the confrontation is almost effortless; the counter-phobic Six confronts from anxiety, they feel scared inside and the confrontation requires overriding their fear, giving it a charged, almost aggressive quality" }, { letter: "B", text: "The Six's confrontation is calmer than the Eight's" }, { letter: "C", text: "Only Eights ever confront bullies" }, { letter: "D", text: "Both types confront with identical internal experiences" }], answer: "A", explanation: "The Eight's confrontation is their natural state, they're comfortable in conflict and it energizes them. The counter-phobic Six is overriding terror to confront, which creates an adrenalized, sometimes disproportionate intensity. Palmer notes that Eights are expanded in conflict; counter-phobic Sixes are fighting to expand against contraction." },
  { id: 1586, type: 8, difficulty: 3 as 1|2|3|4|5, track1Day: 336, track2Day: 386, category: "Misidentification", question: "A person with a loud, commanding presence could be a Type 8 or a social Type 3. They walk into a room and immediately take charge. What indicates Eight?", options: [{ letter: "A", text: "The Eight takes charge regardless of whether the room welcomes it, their authority comes from within and doesn't require the room's permission" }, { letter: "B", text: "The Three is more physically imposing" }, { letter: "C", text: "The Eight asks permission before speaking" }, { letter: "D", text: "Both take charge for identical reasons" }], answer: "A", explanation: "Eights have an internal locus of authority, they don't read the room to calibrate their impact, they set the room's tone. Threes read the room first and then calibrate their leadership style to match what the room respects. The Eight's authority is unconditional; the Three's is adaptive. One is power; the other is performance of power." },
  { id: 1587, type: 8, difficulty: 4 as 1|2|3|4|5, track1Day: 337, track2Day: 387, category: "Stress Signatures", question: "When a Type 8 faces a situation where they genuinely have no control, a terminal diagnosis, an unbeatable bureaucracy, a natural disaster, their disintegration toward Five manifests as:", options: [{ letter: "A", text: "Increased aggression and confrontation" }, { letter: "B", text: "Unprecedented withdrawal, they become secretive, isolated, and cerebral, hoarding information and resources while cutting off from the people who care about them" }, { letter: "C", text: "Becoming more nurturing and emotionally available" }, { letter: "D", text: "Seeking help from as many people as possible" }], answer: "B", explanation: "When Eights cannot fight, they retreat, moving toward Five's withdrawal. The normally expansive Eight becomes small, secretive, and controlled. Riso-Hudson describe this as the Eight's last resort: if they can't control the situation externally, they'll control their exposure to it by disappearing. This withdrawal is alarming to those who know the Eight." },
  { id: 1588, type: 8, difficulty: 3 as 1|2|3|4|5, track1Day: 338, track2Day: 388, category: "Stress Signatures", question: "An Eight's body reveals their stress before their words do. The most common somatic stress pattern for Eights is:", options: [{ letter: "A", text: "Collapsing posture and visible fatigue" }, { letter: "B", text: "Escalating physical intensity, louder voice, more space-occupying posture, quicker to physical action, as if their body is armoring up before a fight they sense coming" }, { letter: "C", text: "Nervous fidgeting and inability to sit still" }, { letter: "D", text: "Stomach problems and loss of appetite" }], answer: "B", explanation: "Eights are body-center types and their stress shows somatically as amplification of physical presence. The body literally expands, jaw tightens, chest broadens, voice drops and intensifies. Somatic Enneagram practitioners note that Eights under stress develop what looks like a physical force field, repelling approach through sheer energetic intensity." },
  { id: 1589, type: 8, difficulty: 4 as 1|2|3|4|5, track1Day: 339, track2Day: 389, category: "Blind Spots", question: "Eights often say 'I just tell it like it is' or 'I'm just being direct.' What is the primary blind spot in this self-assessment?", options: [{ letter: "A", text: "That their 'directness' is often experienced as intimidation, and they systematically underestimate the power differential between themselves and others, what feels like honesty to them feels like an assault to people with less power" }, { letter: "B", text: "That they should be even more direct" }, { letter: "C", text: "That they are actually quite indirect and passive" }, { letter: "D", text: "That directness is never appropriate in professional settings" }], answer: "A", explanation: "The Eight's biggest blind spot is impact, the gap between their intent ('I'm being honest') and others' experience ('I'm being attacked'). Eights genuinely don't feel their own intensity because they live inside it. Palmer notes that Eights must learn that their '3' on the intensity dial is most people's '8.'" },
  { id: 1590, type: 8, difficulty: 3 as 1|2|3|4|5, track1Day: 340, track2Day: 390, category: "Blind Spots", question: "An Eight insists they treat everyone equally and fairly. What pattern might their team see that the Eight cannot?", options: [{ letter: "A", text: "That the Eight actually favors the weakest team members" }, { letter: "B", text: "That the Eight unconsciously tests people for strength, those who push back earn respect and access, while those who submit are subtly dismissed, creating an environment that only rewards those who communicate like the Eight" }, { letter: "C", text: "That the Eight is too gentle with underperformers" }, { letter: "D", text: "That the Eight treats absolutely everyone identically" }], answer: "B", explanation: "Eights have a blind spot around their testing behavior. They unconsciously create strength hierarchies, people who 'stand up to them' are trusted; people who defer are dismissed as weak. The Eight genuinely believes this is meritocratic, but it actually selects for a narrow communication style that mimics their own, excluding many competent people." },
  { id: 1591, type: 8, difficulty: 5 as 1|2|3|4|5, track1Day: 341, track2Day: 391, category: "Growth Edges", question: "What is the most transformative, and terrifying, growth edge for a Type 8?", options: [{ letter: "A", text: "Becoming even more powerful and dominant" }, { letter: "B", text: "Allowing themselves to be genuinely vulnerable without any guarantee of safety, letting someone see their tenderness, fear, or need without controlling the outcome" }, { letter: "C", text: "Learning to suppress their anger completely" }, { letter: "D", text: "Becoming more strategic in their use of power" }], answer: "B", explanation: "The Eight's growth direction is Two, opening the heart. This requires the most frightening thing an Eight can do: showing the soft underbelly they've spent a lifetime armoring. Riso-Hudson describe this as the Eight's 'holy innocence', the discovery that vulnerability is not weakness but the gateway to the intimacy they secretly crave." },
  { id: 1592, type: 8, difficulty: 4 as 1|2|3|4|5, track1Day: 342, track2Day: 392, category: "Growth Edges", question: "A mature Type 8 who has done significant growth work handles a team failure differently from an average Eight. How?", options: [{ letter: "A", text: "They blame the team more harshly to prevent future failures" }, { letter: "B", text: "They own their part of the failure openly, ask the team what they need, and resist the impulse to either fix it unilaterally or assign blame, creating space for collective accountability rather than top-down control" }, { letter: "C", text: "They ignore the failure entirely" }, { letter: "D", text: "They delegate all accountability to a subordinate" }], answer: "B", explanation: "Mature Eights develop what integration toward Two provides: the ability to lead through empowerment rather than control. Instead of 'I'll fix this,' they ask 'what do we need?' This requires the Eight to tolerate not being the strongest person in the room, to let the team's collective wisdom guide the response rather than their individual will." },
  { id: 1593, type: 8, difficulty: 3 as 1|2|3|4|5, track1Day: 343, track2Day: 393, category: "Cultural Variations", question: "In cultures that value hierarchy and respect for elders (e.g., many East Asian and Middle Eastern cultures), young Type 8s often:", options: [{ letter: "A", text: "Effortlessly conform to hierarchical expectations" }, { letter: "B", text: "Experience intense internal conflict between their instinct to assert autonomy and cultural demands for deference, potentially channeling their Eight energy into becoming the most powerful person within the approved hierarchy rather than challenging it" }, { letter: "C", text: "Leave their culture entirely" }, { letter: "D", text: "Lose their Eight traits permanently" }], answer: "B", explanation: "Eights in hierarchical cultures face a unique challenge: their instinct to challenge authority collides with cultural requirements for respect. Many adapt by channeling their dominance into rising within the hierarchy rather than overthrowing it. The drive for control remains, but its expression becomes culturally shaped, they dominate from within the system." },
  { id: 1594, type: 8, difficulty: 4 as 1|2|3|4|5, track1Day: 344, track2Day: 394, category: "Cultural Variations", question: "Female Type 8s in cultures with strict gender expectations face a particular challenge that male Eights do not. What is it?", options: [{ letter: "A", text: "They have no challenges unique to their gender" }, { letter: "B", text: "Their natural assertiveness and comfort with power directly violate feminine gender norms, leading many to be pathologized as 'aggressive' or 'unfeminine', the same behavior praised in men is punished in women" }, { letter: "C", text: "Female Eights are always more successful than male Eights" }, { letter: "D", text: "Female Eights are gentler than male Eights" }], answer: "B", explanation: "Female Eights receive cultural punishment for behavior that's rewarded in male Eights. A forceful male leader is 'strong'; a forceful female leader is 'difficult.' Many female Eights develop strategies, humor, selective vulnerability, or channeling their power through traditionally feminine domains, to express their nature without triggering cultural sanctions." },
  { id: 1595, type: 8, difficulty: 3 as 1|2|3|4|5, track1Day: 345, track2Day: 395, category: "Subtypes Deep Dive", question: "A self-preservation Eight has a well-stocked pantry, a detailed financial plan, and makes sure their family wants for nothing. Friends see a generous provider. The SP Eight's internal experience is:", options: [{ letter: "A", text: "Simple generosity" }, { letter: "B", text: "A need to control their survival domain so thoroughly that no external force can threaten their family's security, the providing is real but it's driven by the Eight's need to never be vulnerable to scarcity" }, { letter: "C", text: "Anxiety about money" }, { letter: "D", text: "Indifference to material security" }], answer: "B", explanation: "SP Eights are the 'satisfaction' subtype per Naranjo, they ensure their material world is fully under control. Their generosity is genuine but strategically motivated: a well-provided-for family is a family that can't be threatened. Chestnut notes SP Eights may look like Twos in their caretaking but the underlying energy is protective control, not emotional neediness." },
  { id: 1596, type: 8, difficulty: 4 as 1|2|3|4|5, track1Day: 346, track2Day: 396, category: "Subtypes Deep Dive", question: "A social Eight is passionate about social justice and spends their energy fighting institutional power on behalf of marginalized groups. What makes this specifically an Eight pattern rather than general activism?", options: [{ letter: "A", text: "Any activist must be an Eight" }, { letter: "B", text: "The SO Eight doesn't just advocate, they instinctively position themselves as the protector-in-chief, and their activism carries a confrontational, almost combative energy that distinguishes it from a Two's service or a One's principled reform" }, { letter: "C", text: "Social Eights are actually the quietest activists" }, { letter: "D", text: "Social Eights focus on individual charity rather than systemic change" }], answer: "B", explanation: "Social Eights are the counter-type, they channel their aggression into protecting groups rather than dominating them. But the Eight energy is unmistakable: they don't write petitions, they confront power directly. Chestnut connects this to 'social duty', the SO Eight feels personally responsible for shielding the vulnerable from injustice, and they do it with full Eight intensity." },
  { id: 1597, type: 8, difficulty: 5 as 1|2|3|4|5, track1Day: 347, track2Day: 397, category: "Subtypes Deep Dive", question: "A sexual Eight in a romantic relationship is intensely possessive and passionate. When their partner maintains an independent friendship the SX Eight finds threatening, the characteristic response is:", options: [{ letter: "A", text: "Calm acceptance of the partner's autonomy" }, { letter: "B", text: "A direct power move, either confronting the friend, demanding the partner choose, or intensifying their own claim on the partner through increased passion and presence, because the SX Eight experiences the intimate bond as their primary domain of control" }, { letter: "C", text: "Passive-aggressive withdrawal" }, { letter: "D", text: "Seeking their own outside friendships in retaliation" }], answer: "B", explanation: "SX Eights are the most emotionally intense and possessive subtype. They experience intimate relationships as their territory, and perceived threats to that territory activate their full Eight response. Chestnut describes them as 'possession', they want complete claiming of and by the partner. This can be experienced as overwhelming devotion or suffocating control." },
  { id: 1598, type: 8, difficulty: 3 as 1|2|3|4|5, track1Day: 348, track2Day: 398, category: "Famous Figures", question: "Martin Luther King Jr. is commonly typed as a Type 8 in the Enneagram community. What aspect of his leadership most clearly reveals Eight energy rather than, say, Type 1 moral conviction?", options: [{ letter: "A", text: "His moral principles alone" }, { letter: "B", text: "His willingness to directly confront power structures, his physical presence in danger zones, and his ability to inspire others through the force of his conviction, he didn't just articulate principles, he embodied power in service of justice" }, { letter: "C", text: "His quiet, behind-the-scenes organizing" }, { letter: "D", text: "His avoidance of direct confrontation with authorities" }], answer: "B", explanation: "King's leadership combined moral vision with unmistakable Eight energy: he put his body on the line, confronted power face-to-face, and projected a force of personality that moved millions. A One might write the principles; an Eight stands in the street. King's integration toward Two's compassion made his Eight power redemptive rather than destructive." },
  { id: 1599, type: 8, difficulty: 4 as 1|2|3|4|5, track1Day: 349, track2Day: 399, category: "Famous Figures", question: "Serena Williams is often discussed as a Type 8 example. What behavioral pattern is most diagnostic?", options: [{ letter: "A", text: "Her quiet demeanor on court" }, { letter: "B", text: "Her refusal to diminish herself in a sport that expected feminine grace, her raw power, intensity, and willingness to express anger on court in an environment that punished her for it, combined with fierce protectiveness of her family" }, { letter: "C", text: "Her focus on being liked by fans and media" }, { letter: "D", text: "Her preference for doubles over singles competition" }], answer: "B", explanation: "Williams embodies the Eight's unapologetic self-expression: she brought full intensity to a sport that punished Black women for showing power, refused to shrink, and confronted unfair treatment directly. Her off-court protectiveness of her children and sister reflects the Eight's integration toward Two, power in service of those they love." },
  { id: 1600, type: 8, difficulty: 3 as 1|2|3|4|5, track1Day: 350, track2Day: 400, category: "Famous Figures", question: "Winston Churchill is frequently typed as an 8w7. What makes the Seven wing evident in his expression of Eight?", options: [{ letter: "A", text: "His quiet, restrained leadership style" }, { letter: "B", text: "His legendary wit, love of luxury, rhetorical flamboyance, and ability to inspire through optimistic defiance, the Seven wing added charisma, humor, and expansiveness to the Eight's raw power" }, { letter: "C", text: "His strict temperance and ascetic lifestyle" }, { letter: "D", text: "His preference for avoiding conflict through diplomacy" }], answer: "B", explanation: "Churchill's 8w7 shows in the combination of Eight's confrontational courage with Seven's expansive appetite: fine champagne, vivid rhetoric, bold strategic gambles, and a refusal to let even war dampen his enjoyment of life. The Seven wing gave his Eight power an infectious, almost celebratory quality that inspired a nation under siege." },
  // ── TYPE 9: The Peacemaker (IDs 1601,1620) ──
  { id: 1601, type: 9, difficulty: 3 as 1|2|3|4|5, track1Day: 351, track2Day: 401, category: "Healthy vs Unhealthy", question: "A Type 9 has strong opinions about a political issue. A healthy Nine and an unhealthy Nine both care deeply. What distinguishes them?", options: [{ letter: "A", text: "The healthy Nine articulates their position clearly even when it creates tension; the unhealthy Nine keeps their opinion to themselves, telling each person what they want to hear" }, { letter: "B", text: "The healthy Nine has no opinions; the unhealthy Nine has too many" }, { letter: "C", text: "Both express themselves identically" }, { letter: "D", text: "The healthy Nine is more passionate than the unhealthy Nine" }], answer: "A", explanation: "Healthy Nines (Levels 1-3) maintain their inner peace while engaging with conflict, they can hold their ground without losing their calm. Unhealthy Nines sacrifice their position to avoid tension, often unconsciously shapeshifting to match whoever they're talking to. Riso-Hudson call this the difference between 'genuine peacemaking' and 'peace-faking.'" },
  { id: 1602, type: 9, difficulty: 4 as 1|2|3|4|5, track1Day: 352, track2Day: 402, category: "Healthy vs Unhealthy", question: "An unhealthy Type 9 has been in a job they dislike for ten years. When asked why they stay, they give various reasons, benefits, convenience, familiarity. What is the actual underlying pattern?", options: [{ letter: "A", text: "They genuinely enjoy the job" }, { letter: "B", text: "The pain of staying has become so familiar it no longer registers as pain, they've narcotized their dissatisfaction through routine, merging with the status quo so completely that they've lost access to what they actually want" }, { letter: "C", text: "They are strategically building experience for a better opportunity" }, { letter: "D", text: "External circumstances genuinely prevent them from leaving" }], answer: "B", explanation: "Unhealthy Nines exhibit what Riso-Hudson call 'self-forgetting', they literally lose track of their own desires. The discomfort of the wrong job fades to background noise through the Nine's narcotizing defenses (routine, distraction, minimization). They're not choosing to stay; they've forgotten they have a choice." },
  { id: 1603, type: 9, difficulty: 3 as 1|2|3|4|5, track1Day: 353, track2Day: 403, category: "Healthy vs Unhealthy", question: "A healthy Type 9 mediating a conflict between two friends demonstrates their gift by:", options: [{ letter: "A", text: "Taking one side to resolve the conflict quickly" }, { letter: "B", text: "Genuinely holding both perspectives without collapsing into either, then articulating a synthesis that makes each person feel truly heard while moving toward resolution" }, { letter: "C", text: "Avoiding the conflict entirely" }, { letter: "D", text: "Telling both friends they're overreacting" }], answer: "B", explanation: "The healthy Nine's gift is genuine omniperspectival awareness, they don't just understand both sides intellectually, they feel both positions from the inside. At Levels 1-3, this becomes transformative mediation: the Nine creates a container where conflict can be held without anyone being diminished. This is the Nine's unique superpower." },
  { id: 1604, type: 9, difficulty: 4 as 1|2|3|4|5, track1Day: 354, track2Day: 404, category: "Misidentification", question: "Both Type 9 and Type 2 are people-pleasing and conflict-avoidant. A person consistently puts others' needs first. What most clearly indicates Nine rather than Two?", options: [{ letter: "A", text: "The Nine puts others first by disappearing, merging with others' agendas without even recognizing they had their own agenda. The Two puts others first by actively giving, they know what they want but suppress it in favor of what others need." }, { letter: "B", text: "Nines are more generous than Twos" }, { letter: "C", text: "Twos never put others first" }, { letter: "D", text: "Both types have identical internal experiences when people-pleasing" }], answer: "A", explanation: "The Nine's people-pleasing is passive and self-erasing; the Two's is active and strategic. A Nine at a restaurant says 'I don't care, whatever everyone else wants.' They mean it, they've genuinely lost access to their preference. A Two at a restaurant says the same thing but is tracking everyone's preferences to ensure they're the one who makes everyone happy." },
  { id: 1605, type: 9, difficulty: 5 as 1|2|3|4|5, track1Day: 355, track2Day: 405, category: "Misidentification", question: "Type 9 and Type 5 can both appear withdrawn, low-energy, and non-reactive. A quiet person sits in a meeting barely participating. What distinguishes a Nine from a Five?", options: [{ letter: "A", text: "The Five is observing with sharp focus, they're taking everything in and processing it internally. The Nine is diffused, their attention is spread across the room's emotional landscape, and they may genuinely have lost track of their own thoughts." }, { letter: "B", text: "The Five is bored; the Nine is interested" }, { letter: "C", text: "The Nine is more intelligent than the Five" }, { letter: "D", text: "Both experience meetings identically" }], answer: "A", explanation: "The quality of attention differs fundamentally. Fives withdraw into focused thought, their mind is a searchlight. Nines withdraw into diffuse awareness, their mind is ambient light. After the meeting, the Five has sharp observations; the Nine may struggle to articulate what they think because they were holding everyone else's perspective simultaneously." },
  { id: 1606, type: 9, difficulty: 3 as 1|2|3|4|5, track1Day: 356, track2Day: 406, category: "Misidentification", question: "A calm, agreeable person who avoids confrontation could be a Type 9 or a phobic Type 6. They both say 'I just want everyone to get along.' What reveals the Nine?", options: [{ letter: "A", text: "The Nine wants harmony because conflict disrupts their inner peace, it's a comfort issue. The Six wants harmony because conflict feels threatening, it's a safety issue." }, { letter: "B", text: "Only Nines want people to get along" }, { letter: "C", text: "Sixes are more peaceful than Nines" }, { letter: "D", text: "Both types have identical relationships to conflict" }], answer: "A", explanation: "Nines experience conflict as a disturbance to their equilibrium, it's literally uncomfortable in their body. Sixes experience conflict as a potential danger, it activates their threat-detection system. Push past the harmony and the Nine becomes stubborn and withdrawn; push past it with the Six and they become anxious and reactive. Different defense, different affect." },
  { id: 1607, type: 9, difficulty: 4 as 1|2|3|4|5, track1Day: 357, track2Day: 407, category: "Stress Signatures", question: "A Type 9 who has been suppressing their needs in a relationship for years reaches a breaking point. Their disintegration toward Six manifests as:", options: [{ letter: "A", text: "Becoming more peaceful and accommodating" }, { letter: "B", text: "Sudden, uncharacteristic anxiety and worst-case thinking, they become suspicious, reactive, and indecisive, and the partner is shocked because the Nine has never expressed this much distress before" }, { letter: "C", text: "Becoming aggressive and confrontational like an Eight" }, { letter: "D", text: "Withdrawing into creative solitude" }], answer: "B", explanation: "Nines disintegrate toward Six, and the shift is dramatic: the normally calm Nine becomes anxious, paranoid, and emotionally reactive. Years of suppressed concerns erupt as Six-like catastrophizing. Palmer notes that the Nine's accumulated, unexpressed frustrations surface as generalized anxiety rather than specific complaints." },
  { id: 1608, type: 9, difficulty: 3 as 1|2|3|4|5, track1Day: 358, track2Day: 408, category: "Stress Signatures", question: "A stressed Type 9's daily routine reveals their narcotization pattern. Which behavior cluster is most characteristic?", options: [{ letter: "A", text: "Intense focus on a single important project" }, { letter: "B", text: "Increased time on low-priority, numbing activities, binge-watching TV, scrolling social media, snacking, or doing busywork, while the genuinely important tasks they're avoiding sit untouched" }, { letter: "C", text: "Aggressive confrontation of everyone around them" }, { letter: "D", text: "Dramatic emotional outbursts followed by apologies" }], answer: "B", explanation: "The Nine's narcotization is their primary defense: they numb themselves through routine, comfort, and low-stakes activity to avoid the discomfort of engaging with what actually matters. Riso-Hudson describe this as 'falling asleep to oneself', the Nine isn't lazy but unconsciously avoiding the inner activation that priorities would require." },
  { id: 1609, type: 9, difficulty: 4 as 1|2|3|4|5, track1Day: 359, track2Day: 409, category: "Blind Spots", question: "A Type 9 genuinely believes they have no anger. Their partner, however, can feel the Nine's anger clearly. What is the Nine's blind spot?", options: [{ letter: "A", text: "They actually don't have anger, the partner is projecting" }, { letter: "B", text: "Their anger is expressed through passive resistance, stubbornness, procrastination, withdrawal, and 'forgetting', and because it never takes direct form, the Nine literally doesn't recognize it as anger" }, { letter: "C", text: "They express anger openly but forget about it afterwards" }, { letter: "D", text: "They only feel anger in dreams" }], answer: "B", explanation: "Nines are body-center types whose primary emotion is anger, but it's the most suppressed anger of any type. It emerges sideways: passive aggression, stubborn refusal, emotional withdrawal, convenient forgetting. The Nine genuinely cannot see this as anger because they define anger only as overt hostility. Palmer calls this 'the anger that doesn't know its own name.'" },
  { id: 1610, type: 9, difficulty: 3 as 1|2|3|4|5, track1Day: 360, track2Day: 410, category: "Blind Spots", question: "A Type 9 says, 'I'm easy. I don't really have preferences.' What can everyone around them see that the Nine cannot?", options: [{ letter: "A", text: "That they genuinely have no preferences" }, { letter: "B", text: "That they clearly do have preferences, they light up around certain foods, activities, and people, but they've suppressed self-awareness of these preferences to avoid the potential conflict of asserting them" }, { letter: "C", text: "That they are difficult and demanding" }, { letter: "D", text: "That they should develop preferences through effort" }], answer: "B", explanation: "Everyone around a Nine can see their preferences, what makes them smile, what they gravitate toward, what makes them withdraw. The Nine's blind spot is extraordinary: they've disconnected from their own wanting so completely that they don't recognize their own desires even when they're acting on them. This is the Nine's self-forgetting at its most fundamental." },
  { id: 1611, type: 9, difficulty: 5 as 1|2|3|4|5, track1Day: 361, track2Day: 411, category: "Growth Edges", question: "What does the Nine's integration toward Three actually look like in practice?", options: [{ letter: "A", text: "They become image-conscious and obsessed with status" }, { letter: "B", text: "They develop the capacity to identify what they want and pursue it with sustained energy, setting personal goals, taking initiative, and tolerating the discomfort of being visible and potentially causing conflict through their achievement" }, { letter: "C", text: "They become workaholics who lose their peace" }, { letter: "D", text: "They start competing with everyone around them" }], answer: "B", explanation: "Integration toward Three gives Nines something revolutionary: agency. They move from 'whatever everyone else wants' to 'here's what I want, and I'm going to pursue it.' Riso-Hudson describe this as the Nine waking up from their trance, they become energized, focused, and effective while retaining their natural warmth and equanimity." },
  { id: 1612, type: 9, difficulty: 4 as 1|2|3|4|5, track1Day: 362, track2Day: 412, category: "Growth Edges", question: "A Nine's therapist suggests they practice expressing a preference when their partner asks 'where should we eat?' The Nine finds this exercise unexpectedly terrifying because:", options: [{ letter: "A", text: "They are afraid of restaurants" }, { letter: "B", text: "Stating a preference means separating from the merged state, it's an act of individuation that unconsciously triggers their deepest fear: that asserting themselves will rupture connection and leave them alone" }, { letter: "C", text: "They are worried about the cost of dining out" }, { letter: "D", text: "They don't like the food at any restaurants" }], answer: "B", explanation: "The Nine's merge defense keeps them connected at the cost of selfhood. Every act of preference is an act of separation, and separation feels like death to the Nine's ego structure. The growth edge is discovering that healthy relationships actually require two separate selves, and that their partner wants to know who they really are." },
  { id: 1613, type: 9, difficulty: 3 as 1|2|3|4|5, track1Day: 363, track2Day: 413, category: "Cultural Variations", question: "In highly collectivist cultures where group harmony is paramount, Type 9 behavior is:", options: [{ letter: "A", text: "Extremely unusual and noticeable" }, { letter: "B", text: "Culturally reinforced and therefore almost invisible, the Nine's natural tendency to merge with the group's agenda is exactly what the culture demands, making it nearly impossible to distinguish type from cultural norm" }, { letter: "C", text: "Actively punished and discouraged" }, { letter: "D", text: "Expressed more intensely than in individualist cultures" }], answer: "B", explanation: "In collectivist cultures, the Nine's pattern is the cultural ideal: prioritize harmony, subsume individual desire for group cohesion, avoid direct confrontation. This makes typing Nines in such cultures extremely difficult, everyone appears Nine-like. Clinicians must look for the Nine's specific quality of self-forgetting rather than just accommodation." },
  { id: 1614, type: 9, difficulty: 4 as 1|2|3|4|5, track1Day: 364, track2Day: 414, category: "Cultural Variations", question: "A Type 9 raised in a highly competitive, individualistic culture (e.g., American startup culture) faces a unique tension. How does it typically manifest?", options: [{ letter: "A", text: "They thrive without any internal conflict" }, { letter: "B", text: "They may adopt the language and appearance of ambition while remaining fundamentally merged with others' agendas, they become the Nine who looks like they're driving but is actually coasting on others' energy and expectations" }, { letter: "C", text: "They completely abandon their Nine tendencies" }, { letter: "D", text: "They become more conflict-oriented than Eights" }], answer: "B", explanation: "Nines in competitive cultures often develop a convincing performance of ambition, they merge with the ambitious culture itself. They may have impressive résumés built not from personal drive but from going along with opportunities others created for them. The growth question remains: 'Is this what I want, or what the current around me is pushing toward?'" },
  { id: 1615, type: 9, difficulty: 3 as 1|2|3|4|5, track1Day: 365, track2Day: 415, category: "Subtypes Deep Dive", question: "A self-preservation Nine has established a deeply comfortable routine: same breakfast, same commute, same evening shows. When their partner suggests a spontaneous weekend trip, the SP Nine:", options: [{ letter: "A", text: "Jumps at the chance for adventure" }, { letter: "B", text: "Feels a deep, almost physical resistance, their routine is how they maintain their equilibrium, and disruption feels threatening to their sense of stability, even if they intellectually know the trip would be enjoyable" }, { letter: "C", text: "Angrily refuses" }, { letter: "D", text: "Immediately agrees without any internal reaction" }], answer: "B", explanation: "SP Nines are the most habitual subtype, Naranjo connects them to 'appetite' and physical comfort as a narcotizing strategy. Their routine isn't just preference; it's a self-regulation system. Disruption threatens the carefully constructed equilibrium that keeps their anxiety (and their anger) at bay. Chestnut notes SP Nines can seem stubborn but are actually self-soothing." },
  { id: 1616, type: 9, difficulty: 4 as 1|2|3|4|5, track1Day: 366, track2Day: 416, category: "Subtypes Deep Dive", question: "A social Nine participates actively in multiple groups, book clubs, community organizations, church groups. To outsiders, they look socially engaged. The hidden Nine pattern beneath this activity is:", options: [{ letter: "A", text: "Genuine passion for all these groups" }, { letter: "B", text: "They participate but rarely lead or express strong opinions within any group, they merge with each group's identity, becoming whatever that group needs, while their own individuality remains unexpressed" }, { letter: "C", text: "They are trying to build a professional network" }, { letter: "D", text: "They attend but secretly dislike all the groups" }], answer: "B", explanation: "Social Nines satisfy their social needs through belonging without asserting. Naranjo connects the SO Nine to 'participation', they join but don't lead, contribute but don't direct. Their group involvement provides connection without the risk of standing out. The pattern becomes visible when you ask: 'What do you personally bring to these groups?' and the Nine struggles to answer." },
  { id: 1617, type: 9, difficulty: 5 as 1|2|3|4|5, track1Day: 367, track2Day: 417, category: "Subtypes Deep Dive", question: "A sexual Nine in a relationship merges so completely with their partner that friends and family lose track of the Nine's independent identity. When the relationship ends, what characteristically happens?", options: [{ letter: "A", text: "They quickly move on because they weren't really invested" }, { letter: "B", text: "They experience a devastating identity crisis, having merged so completely with the partner, they literally don't know who they are alone, and the grief is compounded by the terrifying question of what they actually want when no one is there to merge with" }, { letter: "C", text: "They feel relieved to be independent again" }, { letter: "D", text: "They immediately merge with a new partner" }], answer: "B", explanation: "SX Nines are the most merge-prone subtype, they fuse with the partner's identity, interests, and desires so completely that separation is not just loss of relationship but loss of self. Chestnut describes SX Nines as 'fusion' types whose growth requires learning to maintain a separate sense of self within intimate bonds." },
  { id: 1618, type: 9, difficulty: 3 as 1|2|3|4|5, track1Day: 368, track2Day: 418, category: "Famous Figures", question: "Barack Obama is commonly typed as a Type 9 in the Enneagram community. What aspect of his leadership style most clearly reflects Nine psychology?", options: [{ letter: "A", text: "His aggressive confrontation of political opponents" }, { letter: "B", text: "His signature 'no drama' approach, seeking consensus, integrating opposing viewpoints, maintaining calm under pressure, and sometimes frustrating allies by appearing too accommodating toward adversaries" }, { letter: "C", text: "His flashy, attention-seeking public persona" }, { letter: "D", text: "His preference for unilateral decision-making" }], answer: "B", explanation: "Obama's leadership is textbook Nine: the preternatural calm, the ability to hold multiple perspectives, the preference for consensus over confrontation, and the criticism from allies that he was 'too conciliatory.' His 'no drama' brand reflects the Nine's fundamental orientation: maintain equilibrium, integrate all viewpoints, resist being pushed into polarization." },
  { id: 1619, type: 9, difficulty: 4 as 1|2|3|4|5, track1Day: 369, track2Day: 419, category: "Famous Figures", question: "The Dalai Lama is sometimes typed as a Nine with a One wing. What behavioral evidence distinguishes this from the common alternative typing of One with a Nine wing?", options: [{ letter: "A", text: "His anger at injustice suggests One core" }, { letter: "B", text: "His primary energy is acceptance and equanimity, he leads with Nine's universal embrace first and moral principle second, laughing easily and meeting even hostile questions with warmth before addressing their substance" }, { letter: "C", text: "His strict adherence to rules suggests One core" }, { letter: "D", text: "His organizational skills suggest One core" }], answer: "B", explanation: "The 9w1 versus 1w9 debate hinges on primary energy: does acceptance lead, or does principle lead? The Dalai Lama's default mode is warm, inclusive, and disarming (Nine) with moral clarity emerging within that warmth (One wing). A 1w9 would lead with principle and add Nine's calm as a secondary quality. His laughter comes first; his teaching follows." },
  { id: 1620, type: 9, difficulty: 3 as 1|2|3|4|5, track1Day: 370, track2Day: 420, category: "Famous Figures", question: "Keanu Reeves is frequently typed as a Type 9. Which well-known aspects of his public persona most support this?", options: [{ letter: "A", text: "His aggressive pursuit of fame and status" }, { letter: "B", text: "His unassuming presence despite massive fame, his genuine kindness to strangers, his lack of ego-driven public behavior, and the sense that he is simply 'going along' with life's current while remaining centered and kind" }, { letter: "C", text: "His confrontational interview style" }, { letter: "D", text: "His desire to be the highest-paid actor in Hollywood" }], answer: "B", explanation: "Reeves embodies the healthy Nine: present without being pushy, kind without an agenda, and remarkably unattached to the trappings of his success. His famous subway photo (giving up his seat), his acceptance of reduced pay for coworkers' salaries, and his general 'going with the flow' quality all reflect Nine energy operating from a place of genuine inner peace rather than self-forgetting." },
];
